import React from 'react';
import { Difficulty, QuestionType } from '../types';
import Spinner from './Spinner';
import { useTranslation } from '../LanguageContext';

interface QuizFormProps {
    subject: string;
    setSubject: (value: string) => void;
    numberOfQuestionsToGenerate: number;
    setNumberOfQuestionsToGenerate: (value: number) => void;
    gradeLevel: string;
    setGradeLevel: (value: string) => void;
    difficulty: Difficulty;
    setDifficulty: (value: Difficulty) => void;
    questionType: QuestionType;
    setQuestionType: (value: QuestionType) => void;
    numberOfChoices: number;
    setNumberOfChoices: (value: number) => void;
    isHOTS: boolean;
    setIsHOTS: (value: boolean) => void;
    onSubmit: (e: React.FormEvent) => void;
    isLoading: boolean;
}

const OptionButton: React.FC<{
    value: string | number;
    label: string;
    selectedValue: string | number;
    onClick: (value: any) => void;
}> = ({ value, label, selectedValue, onClick }) => (
    <button
        type="button"
        onClick={() => onClick(value)}
        className={`px-4 py-2 text-sm font-medium rounded-md transition-all duration-200 flex-1
        ${selectedValue === value
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
            }`}
    >
        {label}
    </button>
);

const gradeLevelOptions = [
    { value: "PAUD / TK", labelKey: "grade_levels.preschool" },
    { value: "Kelas 1 SD", labelKey: "grade_levels.grade_1" },
    { value: "Kelas 2 SD", labelKey: "grade_levels.grade_2" },
    { value: "Kelas 3 SD", labelKey: "grade_levels.grade_3" },
    { value: "Kelas 4 SD", labelKey: "grade_levels.grade_4" },
    { value: "Kelas 5 SD", labelKey: "grade_levels.grade_5" },
    { value: "Kelas 6 SD", labelKey: "grade_levels.grade_6" },
    { value: "Kelas 7 SMP", labelKey: "grade_levels.grade_7" },
    { value: "Kelas 8 SMP", labelKey: "grade_levels.grade_8" },
    { value: "Kelas 9 SMP", labelKey: "grade_levels.grade_9" },
    { value: "Kelas 10 SMA", labelKey: "grade_levels.grade_10" },
    { value: "Kelas 11 SMA", labelKey: "grade_levels.grade_11" },
    { value: "Kelas 12 SMA", labelKey: "grade_levels.grade_12" },
    { value: "Mahasiswa", labelKey: "grade_levels.university" },
    { value: "Umum", labelKey: "grade_levels.general" },
];


const QuizForm: React.FC<QuizFormProps> = ({
    subject,
    setSubject,
    numberOfQuestionsToGenerate,
    setNumberOfQuestionsToGenerate,
    gradeLevel,
    setGradeLevel,
    difficulty,
    setDifficulty,
    questionType,
    setQuestionType,
    numberOfChoices,
    setNumberOfChoices,
    isHOTS,
    setIsHOTS,
    onSubmit,
    isLoading
}) => {
    const { t } = useTranslation();

    const handleNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value;
        if (value === '') {
            // Temporarily set to 0 to represent empty state in number type input
            setNumberOfQuestionsToGenerate(0);
            return;
        }

        const num = parseInt(value, 10);
        if (num > 50) {
            setNumberOfQuestionsToGenerate(50);
        } else {
            setNumberOfQuestionsToGenerate(num);
        }
    };

    const handleNumberBlur = () => {
        if (numberOfQuestionsToGenerate < 1) {
            setNumberOfQuestionsToGenerate(1);
        }
    };

    return (
        <form onSubmit={onSubmit} className="w-full max-w-2xl space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="sm:col-span-2">
                    <label htmlFor="subject" className="block text-sm font-medium text-slate-300 mb-2">
                        {t('quiz_generator.subject_label')}
                    </label>
                    <input
                        type="text"
                        id="subject"
                        value={subject}
                        onChange={(e) => setSubject(e.target.value)}
                        placeholder={t('quiz_generator.subject_placeholder')}
                        className="w-full bg-slate-800 border border-slate-600 rounded-md px-4 py-2 focus:ring-2 focus:ring-purple-500 focus:border-purple-500 outline-none transition"
                        required
                    />
                </div>
                 <div>
                    <label htmlFor="numberOfQuestions" className="block text-sm font-medium text-slate-300 mb-2">
                        {t('quiz_generator.number_of_questions_label')}
                    </label>
                    <input
                        type="number"
                        id="numberOfQuestions"
                        value={numberOfQuestionsToGenerate === 0 ? '' : numberOfQuestionsToGenerate}
                        onChange={handleNumberChange}
                        onBlur={handleNumberBlur}
                        min="1"
                        max="50"
                        className={`w-full bg-slate-800 border rounded-md px-4 py-2 focus:ring-2 focus:ring-purple-500 outline-none transition ${numberOfQuestionsToGenerate < 1 ? 'border-red-500 focus:border-red-500' : 'border-slate-600 focus:border-purple-500'}`}
                        required
                    />
                    {numberOfQuestionsToGenerate < 1 && (
                         <p className="text-red-400 text-xs mt-1">{t('quiz_generator.min_question_warning')}</p>
                    )}
                </div>
            </div>


            <div>
                <label htmlFor="gradeLevel" className="block text-sm font-medium text-slate-300 mb-2">
                    {t('quiz_generator.grade_level_label')}
                </label>
                <select
                    id="gradeLevel"
                    value={gradeLevel}
                    onChange={(e) => setGradeLevel(e.target.value)}
                    className="w-full bg-slate-800 border border-slate-600 rounded-md px-4 py-2 focus:ring-2 focus:ring-purple-500 focus:border-purple-500 outline-none transition"
                >
                    {gradeLevelOptions.map(opt => (
                        <option key={opt.value} value={opt.value}>{t(opt.labelKey)}</option>
                    ))}
                </select>
            </div>

            <div>
                <label className="block text-sm font-medium text-slate-300 mb-2">{t('quiz_generator.difficulty_label')}</label>
                <div className="flex space-x-2 bg-slate-800 p-1 rounded-lg">
                    <OptionButton value={Difficulty.Easy} label={t('quiz_generator.difficulty_easy')} selectedValue={difficulty} onClick={setDifficulty} />
                    <OptionButton value={Difficulty.Medium} label={t('quiz_generator.difficulty_medium')} selectedValue={difficulty} onClick={setDifficulty} />
                    <OptionButton value={Difficulty.Hard} label={t('quiz_generator.difficulty_hard')} selectedValue={difficulty} onClick={setDifficulty} />
                </div>
            </div>

            <div>
                <label className="block text-sm font-medium text-slate-300 mb-2">{t('quiz_generator.question_type_label')}</label>
                <div className="flex space-x-2 bg-slate-800 p-1 rounded-lg">
                    <OptionButton value={QuestionType.MultipleChoice} label={t('quiz_generator.question_type_mc')} selectedValue={questionType} onClick={setQuestionType} />
                    <OptionButton value={QuestionType.Essay} label={t('quiz_generator.question_type_essay')} selectedValue={questionType} onClick={setQuestionType} />
                </div>
            </div>

            {questionType === QuestionType.MultipleChoice && (
                 <div>
                    <label className="block text-sm font-medium text-slate-300 mb-2">{t('quiz_generator.choices_label')}</label>
                    <div className="flex space-x-2 bg-slate-800 p-1 rounded-lg">
                        <OptionButton value={4} label={t('quiz_generator.choices_4')} selectedValue={numberOfChoices} onClick={setNumberOfChoices} />
                        <OptionButton value={5} label={t('quiz_generator.choices_5')} selectedValue={numberOfChoices} onClick={setNumberOfChoices} />
                    </div>
                </div>
            )}

            <div className="bg-slate-800 p-3 rounded-lg border border-slate-700">
                <div className="flex items-center">
                    <input
                        id="hots-checkbox"
                        type="checkbox"
                        checked={isHOTS}
                        onChange={(e) => setIsHOTS(e.target.checked)}
                        className="h-5 w-5 rounded bg-slate-700 border-slate-600 text-purple-500 focus:ring-2 focus:ring-offset-0 focus:ring-offset-slate-800 focus:ring-purple-500 cursor-pointer"
                    />
                    <label htmlFor="hots-checkbox" className="ml-3 text-sm font-medium text-slate-200 cursor-pointer">
                        {t('quiz_generator.hots_label')}
                    </label>
                </div>
            </div>


            <button
                type="submit"
                disabled={isLoading || !subject.trim() || numberOfQuestionsToGenerate < 1}
                className="w-full flex justify-center items-center bg-purple-600 hover:bg-purple-700 text-white font-bold py-3 px-4 rounded-md transition-all duration-300 disabled:bg-slate-600 disabled:cursor-not-allowed transform hover:scale-105 disabled:scale-100"
            >
                {isLoading ? <Spinner /> : t('quiz_generator.submit_button')}
            </button>
        </form>
    );
};

export default QuizForm;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Question, QuestionType } from '../types';
import XCircleIcon from './icons/XCircleIcon';
import TrashIcon from './icons/TrashIcon';
import PdfIcon from './icons/PdfIcon';
import ClipboardIcon from './icons/ClipboardIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import DocumentIcon from './icons/DocumentIcon';
import WordIcon from './icons/WordIcon';
import KeyIcon from './icons/KeyIcon';
import GoogleFormIcon from './icons/GoogleFormIcon';
import PrinterIcon from './icons/PrinterIcon';
import Tooltip from './Tooltip';
import { useTranslation } from '../LanguageContext';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, PageBreak } from 'docx';

interface DocumentPanelProps {
  isOpen: boolean;
  onClose: () => void;
  questions: Question[];
  onRemove: (questionId: string) => void;
  onClear: () => void;
  subject: string;
}

declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

// Sub-component to render each question and handle its own MathJax typesetting
const DocumentQuestionItem: React.FC<{ question: Question; index: number; onRemove: (id: string) => void }> = ({ question, index, onRemove }) => {
    const itemRef = useRef<HTMLDivElement>(null);
    const { t } = useTranslation();

    useEffect(() => {
        if (window.MathJax && itemRef.current) {
            window.MathJax.typesetPromise([itemRef.current])
                .catch((err) => console.error('MathJax document item typesetting error:', err));
        }
    }, [question]); // Re-typeset only when this specific question content changes

    return (
        <div ref={itemRef} className="question-item bg-slate-900/50 p-4 rounded-lg relative group prose prose-invert max-w-none">
             <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity not-prose no-print">
                <Tooltip content={t('document_panel.remove_item_tooltip')} position="left">
                    <button 
                        onClick={() => onRemove(question.id)}
                        className="p-1.5 text-slate-500 bg-slate-800 rounded-full hover:text-red-500 hover:bg-slate-700 transition-colors"
                        >
                            <TrashIcon className="w-4 h-4" />
                    </button>
                </Tooltip>
             </div>
            <div className="font-semibold text-slate-200 mb-2">
                <p>
                    <span className="font-bold mr-2">{index + 1}.</span>
                    {question.pertanyaan}
                </p>
            </div>
            {question.tipe === QuestionType.MultipleChoice && question.pilihan && (
                <ol className="choices space-y-1 list-inside list-[lower-alpha] text-slate-300 pl-6">
                    {question.pilihan.map((option, i) => (
                        <li key={i}>{option}</li>
                    ))}
                </ol>
            )}
            {question.tipe === QuestionType.Essay && (
                <div className="mt-2 pl-6 no-print">
                    <p className="text-sm text-slate-400 italic">(Essay answer)</p>
                </div>
            )}
        </div>
    );
};


const DocumentPanel: React.FC<DocumentPanelProps> = ({
  isOpen,
  onClose,
  questions,
  onRemove,
  onClear,
  subject,
}) => {
  const { t, language } = useTranslation();
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  const [showGFormModal, setShowGFormModal] = useState(false);
  const [showGFormConfig, setShowGFormConfig] = useState(true); // Toggle between config and script
  const [isGFormScriptCopied, setIsGFormScriptCopied] = useState(false);
  const gformScriptRef = useRef<HTMLTextAreaElement>(null);

  // Google Form Config State
  const [includeName, setIncludeName] = useState(true);
  const [includeClass, setIncludeClass] = useState(true);
  const [includeAbsentNo, setIncludeAbsentNo] = useState(true);
  const [mcPoints, setMcPoints] = useState(2);
  const [essayPoints, setEssayPoints] = useState(0);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        onClose();
      }
    };
    window.addEventListener('keydown', handleEsc);
    return () => {
      window.removeEventListener('keydown', handleEsc);
    };
  }, [onClose]);

  const formatQuestionsToText = useCallback(() => {
    let text = `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n\n`;
    // Use the questions in their insertion order
    questions.forEach((q, index) => {
      text += `${index + 1}. ${q.pertanyaan}\n`; // Use index for sequential numbering
      if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
        q.pilihan.forEach((option, i) => {
          text += `   ${String.fromCharCode(97 + i)}. ${option}\n`;
        });
      }
      text += '\n';
    });
    return text;
  }, [questions, subject, language]);

  const handleCopy = useCallback(() => {
    const textToCopy = formatQuestionsToText();
    navigator.clipboard.writeText(textToCopy).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }).catch(err => {
        console.error('Failed to copy text: ', err)
    });
  }, [formatQuestionsToText]);

  const handleDownloadAnswers = useCallback(() => {
    if (questions.length === 0) return;

    let content = language === 'id' ? `KUNCI JAWABAN\n` : `ANSWER KEY\n`;
    content += `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n`;
    content += `====================================\n\n`;

    const answerLines = questions.map((q, index) => {
        let line = `${index + 1}) `;
        if (q.tipe === QuestionType.MultipleChoice) {
            const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
            if (correctIndex !== -1) {
                const optionLetter = String.fromCharCode(97 + correctIndex);
                line += `${optionLetter}. ${q.jawaban_benar}`;
            } else {
                line += q.jawaban_benar || (language === 'id' ? 'Jawaban tidak ditemukan' : 'Answer not found');
            }
        } else { // Essay
            line += q.jawaban_esai || (language === 'id' ? 'Tidak ada contoh jawaban.' : 'No sample answer provided.');
        }
        return line;
    });

    content += answerLines.join('\n');


    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const safeSubject = subject.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    link.download = `${language === 'id' ? 'kunci_jawaban' : 'answer_key'}_${safeSubject}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

  }, [questions, subject, language]);

  const handleDownloadWord = useCallback(async () => {
    if (questions.length === 0) return;

    // --- Create Question Section ---
    const children: Paragraph[] = [];

    // Title
    children.push(new Paragraph({
        text: subject,
        heading: HeadingLevel.HEADING_1,
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
    }));

    questions.forEach((q, index) => {
        // Question Text
        children.push(new Paragraph({
            children: [
                new TextRun({
                    text: `${index + 1}. ${q.pertanyaan}`,
                    bold: true,
                })
            ],
            spacing: { before: 200, after: 100 },
        }));

        // Options for Multiple Choice
        if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
            q.pilihan.forEach((option, idx) => {
                const letter = String.fromCharCode(97 + idx); // a, b, c
                children.push(new Paragraph({
                    text: `${letter}. ${option}`,
                    indent: { left: 720 }, // Indent options
                    spacing: { after: 50 },
                }));
            });
        }

        // Space for Essay
        if (q.tipe === QuestionType.Essay) {
            children.push(new Paragraph({ text: "", spacing: { after: 1000 } })); // Add empty space
        }
    });

    // --- Create Answer Key Section ---
    children.push(new Paragraph({
        children: [new PageBreak()]
    }));

    children.push(new Paragraph({
        text: language === 'id' ? 'KUNCI JAWABAN' : 'ANSWER KEY',
        heading: HeadingLevel.HEADING_2,
        alignment: AlignmentType.CENTER,
        spacing: { after: 200 },
    }));

    questions.forEach((q, index) => {
        let answerText = "";
        if (q.tipe === QuestionType.MultipleChoice) {
             const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
             if (correctIndex !== -1) {
                 const letter = String.fromCharCode(97 + correctIndex);
                 answerText = `${letter}. ${q.jawaban_benar}`;
             } else {
                 answerText = q.jawaban_benar || "-";
             }
        } else {
            answerText = q.jawaban_esai || "-";
        }

        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                new TextRun({ text: answerText })
            ],
            spacing: { after: 100 },
        }));
    });


    // Create Document
    const doc = new Document({
        sections: [{
            properties: {},
            children: children,
        }],
    });

    // Generate and Download
    const blob = await Packer.toBlob(doc);
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const safeSubject = subject.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    link.download = `${safeSubject}.docx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);

  }, [questions, subject, language]);

  const handlePrint = () => {
    const contentNode = contentRef.current;
    if (!contentNode) return;

    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><head><title>${language === 'id' ? 'Cetak Soal' : 'Print Questions'}</title>`);

      const printStyles = `
        <style>
          body { 
            font-family: 'Times New Roman', Times, serif; 
            font-size: 12pt; 
            color: #000;
          }
          h1 { font-size: 16pt; margin-bottom: 0.5rem; }
          h2 { font-size: 14pt; margin-bottom: 1.25rem; }

          /* Remove all paragraph spacing for a "no space after paragraph" effect */
          p { 
            margin: 0;
            padding: 0;
            line-height: 1.2; /* Set a tight line-height on paragraphs for single-spacing effect */
          }

          /* Spacing for each question block */
          .question-item {
            margin-bottom: 1rem; /* This is the space *between* questions */
            page-break-inside: avoid;
          }

          /* The div containing the question text */
          .question-item .mb-2 {
              margin-bottom: 0.25rem; /* Small space between question text and choices */
          }

          /* Styling for multiple-choice options list */
          .choices {
            list-style-type: lower-alpha;
            padding-left: 2em; /* Indent choices from the left margin */
            margin: 0; /* Remove default list margins */
          }

          .choices li {
              margin: 0; /* Remove default list item margins */
              padding-left: 0.5em; /* Add a little space between the letter (a.) and the option text */
              line-height: 1.2;
          }

          /* Ensure MathJax formulas are the same size as the surrounding text */
          mjx-container {
            font-size: 1.03em !important; /* A tiny adjustment to make it optically match 12pt serif text */
            vertical-align: -0.05em; /* Minor vertical alignment for better flow with the text line */
          }

          /* Hide elements marked as no-print */
          .no-print { display: none !important; }
        </style>
      `;
      printWindow.document.write(printStyles);

      printWindow.document.write('</head><body>');

      const headerHtml = `<h1>${language === 'id' ? 'Materi' : 'Topic'}: ${subject}</h1><h2>${language === 'id' ? 'Daftar Soal' : 'Question List'}</h2>`;
      printWindow.document.write(headerHtml);

      const contentClone = contentRef.current.cloneNode(true) as HTMLElement;
      // .remove-button cleanup is redundant if .no-print works, but keeping for safety in case of JS manipulation issues
      contentClone.querySelectorAll('.remove-button').forEach(btn => btn.remove());

      printWindow.document.write(contentClone.innerHTML);

      printWindow.document.write('</body></html>');
      printWindow.document.close();
      printWindow.focus();

      printWindow.onload = () => {
        printWindow.print();
        printWindow.close();
      };
    }
  };

  const generateGoogleAppsScript = useCallback(() => {
    const sanitizedSubject = subject.replace(/'/g, "\\'");
    const questionsJSON = JSON.stringify(questions, null, 2);

    const langStrings = language === 'id' ? {
        description: `Kuis tentang ${sanitizedSubject}`,
        logCreated: 'Formulir berhasil dibuat! Buka log (Lihat > Log) untuk melihat URL.',
        logUrl: 'URL Formulir yang dipublikasikan: ',
        logEditUrl: 'URL Editor Formulir: ',
        errorLog: 'Error saat memproses soal #',
        failedDataLog: 'Data soal yang gagal: '
    } : {
        description: `Quiz about ${sanitizedSubject}`,
        logCreated: 'Form created successfully! Check the logs (View > Logs) to see the URL.',
        logUrl: 'Published Form URL: ',
        logEditUrl: 'Form Editor URL: ',
        errorLog: 'Error processing question #',
        failedDataLog: 'Failed question data: '
    };

    // Identity fields logic
    const identityLogic = `
  // --- IDENTITAS SISWA ---
  ${includeName ? `var nameItem = form.addTextItem();
  nameItem.setTitle('Nama Lengkap').setRequired(true);` : ''}

  ${includeClass ? `var classItem = form.addTextItem();
  classItem.setTitle('Kelas').setRequired(true);` : ''}

  ${includeAbsentNo ? `var absentItem = form.addTextItem();
  absentItem.setTitle('Nomor Absen').setRequired(true);` : ''}

  if (nameItem || classItem || absentItem) {
     form.addPageBreakItem().setTitle('Soal Kuis');
  }
    `;

    return `/**
 * Creates a Google Form quiz from a set of questions.
 * Generated by Teacher Admin Machine.
 */

// --- SCRIPT UTAMA ---
function createQuizFromQuestions() {
  var formTitle = '${sanitizedSubject}';
  var questions = ${questionsJSON};

  var form = FormApp.create(formTitle);
  form.setDescription('${langStrings.description}');
  form.setIsQuiz(true);

  ${identityLogic}

  // Loop through each question and add it to the form
  questions.forEach(function(q, index) {
    try {
      var questionNumber = index + 1;
      if (q.tipe === '${QuestionType.MultipleChoice}') {
        addMultipleChoiceQuestion(form, q, questionNumber);
      } else if (q.tipe === '${QuestionType.Essay}') {
        addEssayQuestion(form, q, questionNumber);
      }
    } catch (e) {
      Logger.log('${langStrings.errorLog}' + questionNumber + ': ' + e.toString());
      Logger.log('${langStrings.failedDataLog}' + JSON.stringify(q));
    }
  });

  Logger.log('${langStrings.logCreated}');
  Logger.log('${langStrings.logUrl}' + form.getPublishedUrl());
  Logger.log('${langStrings.logEditUrl}' + form.getEditUrl());
}

// --- FUNGSI PEMBANTU ---

/**
 * Menambahkan soal Pilihan Ganda ke formulir.
 */
function addMultipleChoiceQuestion(form, q, number) {
  var item = form.addMultipleChoiceItem();
  item.setTitle(number + ". " + (q.pertanyaan || ''));

  var choices = (q.pilihan || []).map(function(optionText, index) {
    var optionLetter = String.fromCharCode(97 + index); // a, b, c, ...
    var prefixedOptionText = optionLetter + ". " + optionText;
    return item.createChoice(prefixedOptionText, optionText === q.jawaban_benar);
  });

  item.setChoices(choices);
  item.setPoints(${mcPoints}); // Poin dinamis
  item.setRequired(true);

  if (q.langkah_langkah_jawaban) {
    var feedback = FormApp.createFeedback().setText(q.langkah_langkah_jawaban).build();
    item.setFeedbackForCorrect(feedback);
  }
}

/**
 * Menambahkan soal Esai ke formulir.
 */
function addEssayQuestion(form, q, number) {
  var item = form.addParagraphTextItem();
  item.setTitle(number + ". " + (q.pertanyaan || ''));
  item.setRequired(true);
  item.setPoints(${essayPoints}); // Poin dinamis

  if (q.jawaban_esai) {
    var feedback = FormApp.createFeedback().setText(q.jawaban_esai).build();
    item.setFeedback(feedback);
  }
}
`;
