import React, { useState, useEffect, useRef } from 'react';
import { Question, QuestionType } from '../types';
import RefreshIcon from './icons/RefreshIcon';
import Spinner from './Spinner';
import PlusCircleIcon from './icons/PlusCircleIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import PhotoIcon from './icons/PhotoIcon';
import { useTranslation } from '../LanguageContext';

interface QuestionCardProps {
  question: Question;
  onRegenerate: (questionId: string) => void;
  isRegenerating: boolean;
  onAddToDocument: (question: Question) => void;
  isAddedToDocument: boolean;
  onGenerateImage: (questionId: string) => void;
  isGeneratingImage: boolean;
}

declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

const QuestionCard: React.FC<QuestionCardProps> = ({ 
    question, 
    onRegenerate, 
    isRegenerating, 
    onAddToDocument, 
    isAddedToDocument,
    onGenerateImage,
    isGeneratingImage
}) => {
  const [showAnswer, setShowAnswer] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const { t } = useTranslation();

  useEffect(() => {
    // Reset answer visibility when the question content changes (e.g., after regenerating)
    setShowAnswer(false);
  }, [question]);

  useEffect(() => {
    // Typeset the entire card whenever the question content changes.
    // This handles initial rendering, regeneration, and answer visibility changes robustly.
    if (window.MathJax && cardRef.current) {
        window.MathJax.typesetPromise([cardRef.current])
            .catch((err) => console.error('MathJax card typesetting error:', err));
    }
  }, [question, showAnswer]); // Rerun if question changes or answer is toggled

  const isMultipleChoice = question.tipe === QuestionType.MultipleChoice;
  const solutionText = question.langkah_langkah_jawaban || '';
  const isNumberedList = /^\s*1\./.test(solutionText);

  // Parse solution steps only if it's a numbered list
  const solutionSteps = isNumberedList
    ? solutionText
        .split(/\s*(?=\d+\.\s*)/)
        .map(step => step.trim())
        .filter(step => {
            const match = step.match(/^\d+\.\s*(.*)/s);
            return match && match[1] && match[1].trim() !== '';
        })
    : [];

  return (
    <div ref={cardRef} className="relative bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-lg p-6 shadow-lg transform transition-transform duration-300 hover:scale-[1.02] hover:border-purple-500">

      {isRegenerating && (
        <div className="absolute inset-0 bg-slate-900/70 backdrop-blur-sm flex items-center justify-center rounded-lg z-10">
          <Spinner className="w-8 h-8"/>
        </div>
      )}

      <div>
        <div className="flex justify-between items-start">
            <div className="flex-grow pr-4">
            <div className="text-lg font-semibold text-slate-200 mb-4 prose prose-invert max-w-none">
                <span className="text-purple-400 font-bold mr-2">{question.nomor}.</span>
                {question.pertanyaan}
            </div>
            </div>
            <div className="flex flex-col items-center gap-2 -mt-2 -mr-2">
                <button
                    onClick={() => onAddToDocument(question)}
                    disabled={isAddedToDocument}
                    className="p-2 text-slate-400 transition-colors duration-200 rounded-full hover:bg-slate-700/50 disabled:cursor-not-allowed"
                    title={isAddedToDocument ? t('question_card.added_to_document') : t('question_card.add_to_document')}
                    aria-label={isAddedToDocument ? t('question_card.added_aria_label', {number: question.nomor}) : t('question_card.add_aria_label', {number: question.nomor})}
                >
                    {isAddedToDocument ? <CheckCircleIcon className="w-5 h-5 text-green-500"/> : <PlusCircleIcon className="w-5 h-5 hover:text-purple-400"/>}
                </button>
                <button
                    onClick={() => onRegenerate(question.id)}
                    disabled={isRegenerating}
                    className="p-2 text-slate-400 hover:text-purple-400 transition-colors duration-200 rounded-full hover:bg-slate-700/50 disabled:cursor-not-allowed disabled:opacity-50"
                    title={t('question_card.regenerate_tooltip')}
                    aria-label={t('question_card.regenerate_aria_label', {number: question.nomor})}
                >
                    <RefreshIcon className="w-5 h-5" />
                </button>
            </div>
        </div>

        {/* Image Section */}
        {question.image_url ? (
            <div className="mb-4 relative group">
                <img src={question.image_url} alt="Question Illustration" className="rounded-lg max-h-64 mx-auto border border-slate-600 shadow-md" />
                <button
                    onClick={() => onGenerateImage(question.id)}
                    className="absolute top-2 right-2 p-1.5 bg-slate-900/80 rounded-full text-slate-300 hover:text-white opacity-0 group-hover:opacity-100 transition-opacity"
                    title={t('question_card.regenerate_image')}
                >
                    <RefreshIcon className="w-4 h-4"/>
                </button>
            </div>
        ) : question.image_prompt ? (
            <div className="mb-4 flex justify-center">
                <button
                    onClick={() => onGenerateImage(question.id)}
                    disabled={isGeneratingImage}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-700 hover:bg-slate-600 text-slate-300 rounded-md text-sm transition-colors border border-dashed border-slate-500"
                >
                    {isGeneratingImage ? <Spinner className="w-4 h-4" /> : <PhotoIcon className="w-4 h-4" />}
                    {isGeneratingImage ? t('question_card.generating_image') : t('question_card.generate_image')}
                </button>
            </div>
        ) : null}


        {isMultipleChoice && question.pilihan && (
            <div className="space-y-3 mb-4 prose prose-invert max-w-none">
            {question.pilihan.map((option, index) => {
                const isCorrect = option === question.jawaban_benar;
                const optionLetter = String.fromCharCode(97 + index);
                const cleanOption = option.replace(/^[A-Ea-e]\.\s*/, '');

                return (
                <div
                    key={index}
                    className={`p-3 rounded-md text-sm transition-colors duration-300 not-prose ${
                    showAnswer
                        ? isCorrect
                        ? 'bg-green-500/20 border border-green-500 text-green-300'
                        : 'bg-slate-700/50'
                        : 'bg-slate-700/50 hover:bg-slate-700 cursor-pointer'
                    }`}
                >
                    <span className="font-mono mr-3 text-purple-400">{optionLetter}.</span>{cleanOption}
                </div>
                );
            })}
            </div>
        )}
      </div>


      <div className="mt-4 pt-4 border-t border-slate-700">
        <button
          onClick={() => setShowAnswer(!showAnswer)}
          className="text-sm font-semibold text-purple-400 hover:text-purple-300 transition-colors"
        >
          {showAnswer ? t('question_card.hide_answer') : t('question_card.show_answer')}
        </button>
        {showAnswer && (
          <div className="mt-3 space-y-4">
            <div className="p-4 bg-slate-900/70 rounded-md prose prose-invert max-w-none text-sm text-slate-300">
                <span className="font-bold text-green-400">{t('question_card.answer_label')}: </span>
                {isMultipleChoice ? question.jawaban_benar : question.jawaban_esai}
            </div>

            {solutionText && (
                <div className="p-4 bg-slate-800/60 rounded-md text-sm text-slate-400 border border-slate-700">
                    <h4 className="font-bold text-yellow-400 text-base mb-3">{t('question_card.solution_label')}:</h4>
                    {isNumberedList ? (
                         <ul className="text-slate-300 prose prose-invert max-w-none">
                            {solutionSteps.map((step, index) => {
                                const match = step.match(/^(\d+\.)\s*(.*)/s);
                                if (!match) return null;

                                const stepNumber = match[1];
                                const stepText = match[2];

                                return (
                                <li key={index} className="flex items-start mb-4 last:mb-0 not-prose">
                                    <span className="font-bold text-purple-400 mr-3 shrink-0">{stepNumber}</span>
                                    <span className="flex-1">{stepText}</span>
                                </li>
                                );
                            })}
                        </ul>
                    ) : (
                        <div className="text-slate-300 prose prose-invert max-w-none">
                           <p>{solutionText}</p>
                        </div>
                    )}
                </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default QuestionCard;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Difficulty, QuestionType, Question } from './types';
import { generateQuiz, addMoreQuizQuestions, regenerateSingleQuestion, generateQuestionImage } from './services/geminiService';
import QuizForm from './components/QuizForm';
import QuestionCard from './components/QuestionCard';
import SparklesIcon from './components/icons/SparklesIcon';
import Spinner from './components/Spinner';
import DocumentPanel from './components/DocumentPanel';
import FloatingActionButton from './components/FloatingActionButton';
import ChevronLeftIcon from './components/icons/ChevronLeftIcon';
import { useTranslation } from './LanguageContext';
import LanguageSwitcher from './components/LanguageSwitcher';


declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

interface QuizGeneratorProps {
    onNavigateBack: () => void;
}

const QuizGenerator: React.FC<QuizGeneratorProps> = ({ onNavigateBack }) => {
    const { t, language } = useTranslation();
    const [subject, setSubject] = useState('');
    const [gradeLevel, setGradeLevel] = useState<string>('Umum');
    const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.Medium);
    const [questionType, setQuestionType] = useState<QuestionType>(QuestionType.MultipleChoice);
    const [numberOfChoices, setNumberOfChoices] = useState<number>(4);
    const [numberOfQuestionsToGenerate, setNumberOfQuestionsToGenerate] = useState<number>(5);
    const [isHOTS, setIsHOTS] = useState(false);
    const [questions, setQuestions] = useState<Question[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isAddingMore, setIsAddingMore] = useState(false);
    const [regeneratingQuestionId, setRegeneratingQuestionId] = useState<string | null>(null);
    const [generatingImageQuestionId, setGeneratingImageQuestionId] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [documentQuestions, setDocumentQuestions] = useState<Question[]>([]);
    const [isDocumentPanelOpen, setIsDocumentPanelOpen] = useState(false);
    const subtitleRef = useRef<HTMLParagraphElement>(null);
    const questionsContainerRef = useRef<HTMLDivElement>(null);


    useEffect(() => {
        if (window.MathJax && subtitleRef.current) {
          window.MathJax.typesetPromise([subtitleRef.current])
            .catch((err) => console.error('MathJax subtitle typesetting error:', err));
        }
    }, [t]);


    const handleGenerateQuiz = useCallback(async (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!subject.trim()) {
            setError(t('quiz_generator.error_empty_subject'));
            return;
        }

        setIsLoading(true);
        setError(null);
        setQuestions([]);

        try {
            const generatedQuestions = await generateQuiz(subject, difficulty, questionType, numberOfChoices, language, gradeLevel, isHOTS, numberOfQuestionsToGenerate);
            setQuestions(generatedQuestions);
        } catch (err) {
            setError(err instanceof Error ? err.message : t('quiz_generator.error_unknown'));
        } finally {
            setIsLoading(false);
        }
    }, [subject, difficulty, questionType, numberOfChoices, t, language, gradeLevel, isHOTS, numberOfQuestionsToGenerate]);

    const handleAddMore = useCallback(async () => {
        setIsAddingMore(true);
        setError(null);
        try {
            const newQuestions = await addMoreQuizQuestions(subject, difficulty, questionType, numberOfChoices, questions, language, gradeLevel, isHOTS, numberOfQuestionsToGenerate);
            const renumberedNewQuestions = newQuestions.map((q, index) => ({
                ...q,
                nomor: questions.length + index + 1,
            }));
            setQuestions(prev => [...prev, ...renumberedNewQuestions]);
        } catch (err)
 {
            setError(err instanceof Error ? err.message : t('quiz_generator.error_add_more'));
        } finally {
            setIsAddingMore(false);
            setTimeout(() => {
                questionsContainerRef.current?.lastElementChild?.scrollIntoView({ behavior: 'smooth', block: 'end' });
            }, 100);
        }
    }, [subject, difficulty, questionType, numberOfChoices, questions, t, language, gradeLevel, isHOTS, numberOfQuestionsToGenerate]);

    const handleRegenerateQuestion = useCallback(async (questionId: string) => {
        const questionToReplace = questions.find(q => q.id === questionId);
        if (!questionToReplace) return;

        setRegeneratingQuestionId(questionId);
        setError(null);
        try {
            const newContentQuestion = await regenerateSingleQuestion(subject, difficulty, questionType, numberOfChoices, questions, questionToReplace, language, gradeLevel, isHOTS);

            const newQuestion: Question = {
                ...newContentQuestion,
                id: questionId,
                nomor: questionToReplace.nomor,
            };

            setQuestions(prevQuestions => 
                prevQuestions.map(q => q.id === questionId ? newQuestion : q)
            );
             setDocumentQuestions(prevDocQuestions =>
                prevDocQuestions.map(q => q.id === questionId ? newQuestion : q)
            );
        } catch (err) {
            setError(err instanceof Error ? err.message : t('quiz_generator.error_regenerate'));
        } finally {
            setRegeneratingQuestionId(null);
        }
    }, [subject, difficulty, questionType, numberOfChoices, questions, t, language, gradeLevel, isHOTS]);

    const handleGenerateImage = useCallback(async (questionId: string) => {
        const question = questions.find(q => q.id === questionId);
        if (!question || !question.image_prompt) return;

        setGeneratingImageQuestionId(questionId);
        setError(null);

        try {
            const imageUrl = await generateQuestionImage(question.image_prompt);

            setQuestions(prev => prev.map(q => 
                q.id === questionId ? { ...q, image_url: imageUrl } : q
            ));

            setDocumentQuestions(prev => prev.map(q => 
                q.id === questionId ? { ...q, image_url: imageUrl } : q
            ));

        } catch (err) {
            console.error(err);
            // Optionally set error specific to image generation
        } finally {
            setGeneratingImageQuestionId(null);
        }
    }, [questions]);

    const handleAddQuestionToDocument = useCallback((question: Question) => {
        setDocumentQuestions(prev => {
            if (prev.some(q => q.id === question.id)) {
                return prev;
            }
            return [...prev, question];
        });
    }, []);

    const handleRemoveQuestionFromDocument = useCallback((questionId: string) => {
        setDocumentQuestions(prev => prev.filter(q => q.id !== questionId));
    }, []);

    const handleClearDocument = useCallback(() => {
        setDocumentQuestions([]);
    }, []);

    const isAllSelected = questions.length > 0 && questions.every(q => documentQuestions.some(docQ => docQ.id === q.id));

    const handleSelectAllToggle = useCallback(() => {
        const currentQuestionIds = new Set(questions.map(q => q.id));

        if (isAllSelected) {
            setDocumentQuestions(prev => prev.filter(docQ => !currentQuestionIds.has(docQ.id)));
        } else {
            setDocumentQuestions(prev => {
                const existingIds = new Set(prev.map(q => q.id));
                const newQuestionsToAdd = questions.filter(q => !existingIds.has(q.id));
                return [...prev, ...newQuestionsToAdd];
            });
        }
    }, [isAllSelected, questions]);


    return (
        <div className="min-h-screen font-sans p-4 sm:p-6 lg:p-8">
            <main className="max-w-4xl mx-auto flex flex-col items-center space-y-10">
                <div className="w-full flex justify-between items-center">
                    <button onClick={onNavigateBack} className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors text-sm">
                        <ChevronLeftIcon className="w-4 h-4" />
                        {t('back_to_home')}
                    </button>
                    <LanguageSwitcher />
                </div>

                <header className="text-center -mt-12">
                    <div className="inline-flex items-center justify-center gap-3 mb-2">
                         <SparklesIcon className="w-8 h-8 text-purple-400" />
                         <h1 className="text-3xl sm:text-4xl font-extrabold tracking-tight bg-gradient-to-r from-purple-400 to-pink-500 text-transparent bg-clip-text">
                            {t('quiz_generator.title')}
                        </h1>
                    </div>
                    <p ref={subtitleRef} className="text-slate-400 max-w-2xl">
                        {t('quiz_generator.description')}
                    </p>
                </header>

                <div className="w-full p-6 bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-xl shadow-2xl">
                    <QuizForm
                        subject={subject}
                        setSubject={setSubject}
                        numberOfQuestionsToGenerate={numberOfQuestionsToGenerate}
                        setNumberOfQuestionsToGenerate={setNumberOfQuestionsToGenerate}
                        gradeLevel={gradeLevel}
                        setGradeLevel={setGradeLevel}
                        difficulty={difficulty}
                        setDifficulty={setDifficulty}
                        questionType={questionType}
                        setQuestionType={setQuestionType}
                        numberOfChoices={numberOfChoices}
                        setNumberOfChoices={setNumberOfChoices}
                        isHOTS={isHOTS}
                        setIsHOTS={setIsHOTS}
                        onSubmit={handleGenerateQuiz}
                        isLoading={isLoading}
                    />
                </div>

                {error && (
                    <div className="w-full max-w-2xl p-4 text-center bg-red-500/20 border border-red-500 text-red-300 rounded-lg">
                        <p><span className="font-bold">Oops!</span> {error}</p>
                    </div>
                )}

                {isLoading && (
                    <div className="flex flex-col items-center justify-center space-y-3 p-8">
                        <div className="w-10 h-10 border-4 border-t-transparent border-purple-500 rounded-full animate-spin"></div>
                        <p className="text-slate-400">{t('quiz_generator.loading_message')}</p>
                    </div>
                )}

                {questions.length > 0 && (
                    <div ref={questionsContainerRef} className="w-full space-y-6">
                        <div className="flex justify-between items-center">
                            <h2 className="text-2xl font-bold text-slate-200">{t('quiz_generator.results_title')}</h2>
                             <div className="flex items-center gap-2">
                                <label htmlFor="selectAll" className="text-sm text-slate-300 select-none cursor-pointer">
                                    {t('quiz_generator.select_all')}
                                </label>
                                <input
                                    type="checkbox"
                                    id="selectAll"
                                    checked={isAllSelected}
                                    onChange={handleSelectAllToggle}
                                    className="h-5 w-5 rounded bg-slate-700 border-slate-600 text-purple-500 focus:ring-2 focus:ring-offset-0 focus:ring-offset-slate-800 focus:ring-purple-500 cursor-pointer"
                                />
                            </div>
                        </div>
                        {questions.map((q) => (
                           <QuestionCard 
                            key={q.id} 
                            question={q} 
                            onRegenerate={handleRegenerateQuestion}
                            isRegenerating={regeneratingQuestionId === q.id}
                            onAddToDocument={handleAddQuestionToDocument}
                            isAddedToDocument={documentQuestions.some(docQ => docQ.id === q.id)}
                            onGenerateImage={handleGenerateImage}
                            isGeneratingImage={generatingImageQuestionId === q.id}
                           />
                        ))}

                        {!isLoading && (
                            <div className="flex justify-center pt-4">
                                <button
                                    onClick={handleAddMore}
                                    disabled={isAddingMore}
                                    className="flex items-center justify-center gap-2 px-6 py-3 border border-purple-500 text-purple-400 font-semibold rounded-lg transition-all duration-300 hover:bg-purple-500/20 disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    {isAddingMore ? <Spinner /> : <SparklesIcon className="w-5 h-5" />}
                                    {isAddingMore ? t('quiz_generator.adding_more') : t('quiz_generator.add_more_button', { count: numberOfQuestionsToGenerate })}
                                </button>
                            </div>
                        )}
                    </div>
                )}
            </main>

            {questions.length > 0 && (
                <FloatingActionButton
                    count={documentQuestions.length}
                    onClick={() => setIsDocumentPanelOpen(true)}
                />
            )}

            <DocumentPanel
                isOpen={isDocumentPanelOpen}
                onClose={() => setIsDocumentPanelOpen(false)}
                questions={documentQuestions}
                onRemove={handleRemoveQuestionFromDocument}
                onClear={handleClearDocument}
                subject={subject}
            />
        </div>
    );
};

export default QuizGenerator;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Question, QuestionType } from '../types';
import XCircleIcon from './icons/XCircleIcon';
import TrashIcon from './icons/TrashIcon';
import PdfIcon from './icons/PdfIcon';
import ClipboardIcon from './icons/ClipboardIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import DocumentIcon from './icons/DocumentIcon';
import WordIcon from './icons/WordIcon';
import KeyIcon from './icons/KeyIcon';
import GoogleFormIcon from './icons/GoogleFormIcon';
import PrinterIcon from './icons/PrinterIcon';
import Tooltip from './Tooltip';
import { useTranslation } from '../LanguageContext';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, PageBreak } from 'docx';

interface DocumentPanelProps {
  isOpen: boolean;
  onClose: () => void;
  questions: Question[];
  onRemove: (questionId: string) => void;
  onClear: () => void;
  subject: string;
}

declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

// Sub-component to render each question and handle its own MathJax typesetting
const DocumentQuestionItem: React.FC<{ question: Question; index: number; onRemove: (id: string) => void }> = ({ question, index, onRemove }) => {
    const itemRef = useRef<HTMLDivElement>(null);
    const { t } = useTranslation();

    useEffect(() => {
        if (window.MathJax && itemRef.current) {
            window.MathJax.typesetPromise([itemRef.current])
                .catch((err) => console.error('MathJax document item typesetting error:', err));
        }
    }, [question]); // Re-typeset only when this specific question content changes

    return (
        <div ref={itemRef} className="question-item bg-slate-900/50 p-4 rounded-lg relative group prose prose-invert max-w-none">
             <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity not-prose no-print">
                <Tooltip content={t('document_panel.remove_item_tooltip')} position="left">
                    <button 
                        onClick={() => onRemove(question.id)}
                        className="p-1.5 text-slate-500 bg-slate-800 rounded-full hover:text-red-500 hover:bg-slate-700 transition-colors"
                        >
                            <TrashIcon className="w-4 h-4" />
                    </button>
                </Tooltip>
             </div>
            <div className="font-semibold text-slate-200 mb-2">
                <p>
                    <span className="font-bold mr-2">{index + 1}.</span>
                    {question.pertanyaan}
                </p>
            </div>

            {question.image_url && (
                <div className="my-2">
                    <img src={question.image_url} alt="Question Diagram" className="rounded-lg max-h-48 border border-slate-600" />
                </div>
            )}

            {question.tipe === QuestionType.MultipleChoice && question.pilihan && (
                <ol className="choices space-y-1 list-inside list-[lower-alpha] text-slate-300 pl-6">
                    {question.pilihan.map((option, i) => (
                        <li key={i}>{option}</li>
                    ))}
                </ol>
            )}
            {question.tipe === QuestionType.Essay && (
                <div className="mt-2 pl-6 no-print">
                    <p className="text-sm text-slate-400 italic">(Essay answer)</p>
                </div>
            )}
        </div>
    );
};


const DocumentPanel: React.FC<DocumentPanelProps> = ({
  isOpen,
  onClose,
  questions,
  onRemove,
  onClear,
  subject,
}) => {
  const { t, language } = useTranslation();
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  const [showGFormModal, setShowGFormModal] = useState(false);
  const [showGFormConfig, setShowGFormConfig] = useState(true); // Toggle between config and script
  const [isGFormScriptCopied, setIsGFormScriptCopied] = useState(false);
  const gformScriptRef = useRef<HTMLTextAreaElement>(null);

  // Google Form Config State
  const [includeName, setIncludeName] = useState(true);
  const [includeClass, setIncludeClass] = useState(true);
  const [includeAbsentNo, setIncludeAbsentNo] = useState(true);
  const [mcPoints, setMcPoints] = useState(2);
  const [essayPoints, setEssayPoints] = useState(0);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        onClose();
      }
    };
    window.addEventListener('keydown', handleEsc);
    return () => {
      window.removeEventListener('keydown', handleEsc);
    };
  }, [onClose]);

  const formatQuestionsToText = useCallback(() => {
    let text = `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n\n`;
    // Use the questions in their insertion order
    questions.forEach((q, index) => {
      text += `${index + 1}. ${q.pertanyaan}\n`; // Use index for sequential numbering
      if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
        q.pilihan.forEach((option, i) => {
          text += `   ${String.fromCharCode(97 + i)}. ${option}\n`;
        });
      }
      text += '\n';
    });
    return text;
  }, [questions, subject, language]);

  const handleCopy = useCallback(() => {
    const textToCopy = formatQuestionsToText();
    navigator.clipboard.writeText(textToCopy).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }).catch(err => {
        console.error('Failed to copy text: ', err)
    });
  }, [formatQuestionsToText]);

  const handleDownloadAnswers = useCallback(() => {
    if (questions.length === 0) return;

    let content = language === 'id' ? `KUNCI JAWABAN\n` : `ANSWER KEY\n`;
    content += `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n`;
    content += `====================================\n\n`;

    const answerLines = questions.map((q, index) => {
        let line = `${index + 1}) `;
        if (q.tipe === QuestionType.MultipleChoice) {
            const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
            if (correctIndex !== -1) {
                const optionLetter = String.fromCharCode(97 + correctIndex);
                line += `${optionLetter}. ${q.jawaban_benar}`;
            } else {
                line += q.jawaban_benar || (language === 'id' ? 'Jawaban tidak ditemukan' : 'Answer not found');
            }
        } else { // Essay
            line += q.jawaban_esai || (language === 'id' ? 'Tidak ada contoh jawaban.' : 'No sample answer provided.');
        }
        return line;
    });

    content += answerLines.join('\n');


    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const safeSubject = subject.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    link.download = `${language === 'id' ? 'kunci_jawaban' : 'answer_key'}_${safeSubject}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

  }, [questions, subject, language]);

  const handleDownloadWord = useCallback(async () => {
    if (questions.length === 0) return;

    // --- Create Question Section ---
    const children: Paragraph[] = [];

    // Title
    children.push(new Paragraph({
        text: subject,
        heading: HeadingLevel.HEADING_1,
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
    }));

    questions.forEach((q, index) => {
        // Question Text
        children.push(new Paragraph({
            children: [
                new TextRun({
                    text: `${index + 1}. ${q.pertanyaan}`,
                    bold: true,
                })
            ],
            spacing: { before: 200, after: 100 },
        }));

        // Note: Adding images to DOCX from base64 client-side with 'docx' library requires more complex blob handling. 
        // For simplicity in this implementation, we focus on text. Images are supported in Print/PDF view.
        if (q.image_url) {
             children.push(new Paragraph({
                children: [
                    new TextRun({
                        text: `[Image for Question ${index+1} available in PDF view]`,
                        italics: true,
                        color: "666666"
                    })
                ],
                spacing: { after: 100 },
            }));
        }

        // Options for Multiple Choice
        if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
            q.pilihan.forEach((option, idx) => {
                const letter = String.fromCharCode(97 + idx); // a, b, c
                children.push(new Paragraph({
                    text: `${letter}. ${option}`,
                    indent: { left: 720 }, // Indent options
                    spacing: { after: 50 },
                }));
            });
        }

        // Space for Essay
        if (q.tipe === QuestionType.Essay) {
            children.push(new Paragraph({ text: "", spacing: { after: 1000 } })); // Add empty space
        }
    });

    // --- Create Answer Key Section ---
    children.push(new Paragraph({
        children: [new PageBreak()]
    }));

    children.push(new Paragraph({
        text: language === 'id' ? 'KUNCI JAWABAN' : 'ANSWER KEY',
        heading: HeadingLevel.HEADING_2,
        alignment: AlignmentType.CENTER,
        spacing: { after: 200 },
    }));

    questions.forEach((q, index) => {
        let answerText = "";
        if (q.tipe === QuestionType.MultipleChoice) {
             const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
             if (correctIndex !== -1) {
                 const letter = String.fromCharCode(97 + correctIndex);
                 answerText = `${letter}. ${q.jawaban_benar}`;
             } else {
                 answerText = q.jawaban_benar || "-";
             }
        } else {
            answerText = q.jawaban_esai || "-";
        }

        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                new TextRun({ text: answerText })
            ],
            spacing: { after: 100 },
        }));
    });


    // Create Document
    const doc = new Document({
        sections: [{
            properties: {},
            children: children,
        }],
    });

    // Generate and Download
    const blob = await Packer.toBlob(doc);
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const safeSubject = subject.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    link.download = `${safeSubject}.docx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);

  }, [questions, subject, language]);

