    const existingQuestionTexts = allOtherQuestions.map(q => `- "${q.pertanyaan}"`).join('\n');
    let rules = formattingRules(difficulty, questionType, numberOfChoices, language, gradeLevel, isHOTS);

    if (language === 'en') {
        rules = rules.replace(
