export interface GradedEssay {
    score: number;
    feedback: string;
}

export const gradeEssayAnswer = async (studentAnswer: string, referenceAnswer: string, maxScore: number = 10): Promise<GradedEssay> => {
    const prompt = `
You are an expert teacher/grader. Your task is to grade a student's essay answer based *strictly* on a reference key answer.

Input:
- Reference Answer (Key): "${referenceAnswer}"
- Student Answer: "${studentAnswer}"
- Maximum Possible Score: ${maxScore}

Rubric (Scale 0 to ${maxScore}):
- 0: Jawaban kosong, tidak relevan, atau salah total.
- ~${Math.floor(maxScore * 0.3)}: Jawaban menyinggung topik tapi sangat kurang tepat/lengkap.
- ~${Math.floor(maxScore * 0.6)}: Jawaban cukup baik, poin utama ada tapi detail kurang atau ada sedikit kesalahan.
- ~${Math.floor(maxScore * 0.85)}: Jawaban sangat baik, hampir sempurna.
- ${maxScore}: Jawaban sempurna, sesuai konteks dan referensi.

Instructions:
- Compare the meaning, not just the exact words (semantic similarity).
- Be fair and consistent.
- If the student answer is empty or just "-", return score 0.

Output:
Return a valid JSON object with the following structure:
{
  "score": integer (0 to ${maxScore}),
  "feedback": "A very brief (max 10 words) justification in Indonesian."
}
`;

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            score: { type: Type.INTEGER },
            feedback: { type: Type.STRING },
        },
        required: ["score", "feedback"],
    };

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash", 
            contents: prompt,
            config: { responseMimeType: "application/json", responseSchema },
        });
        const jsonText = response.text.trim();
        return JSON.parse(jsonText);
    } catch (error) {
        console.error("Error grading essay:", error);
        return { score: 0, feedback: "Error grading." };
    }
};

