           1. Gaya Belajar (paragraf yang menjelaskan cara terbaik bagi mereka untuk belajar).
           2. Kekuatan (daftar 3-5 kekuatan utama).
           3. Rekomendasi Karir (3 kemungkinan karir dengan deskripsi singkat).

           Kembalikan JSON.`;

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            learningStyle: { type: Type.STRING },
            strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
            careerRecommendations: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                    },
                    required: ["title", "description"],
                },
            },
        },
        required: ["learningStyle", "strengths", "careerRecommendations"],
    };

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        return JSON.parse(response.text.trim());
    } catch (error) {
        console.error("Error generating final report:", error);
        throw new Error("Failed to generate final report.");
    }
};

