const DocumentPanel: React.FC<DocumentPanelProps> = ({
  isOpen,
  onClose,
  questions,
  onRemove,
  onClear,
  subject,
}) => {
  const { t, language } = useTranslation();
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  const [showGFormModal, setShowGFormModal] = useState(false);
  const [showGFormConfig, setShowGFormConfig] = useState(true); 
  const [isGFormScriptCopied, setIsGFormScriptCopied] = useState(false);
  const gformScriptRef = useRef<HTMLTextAreaElement>(null);

  const [includeName, setIncludeName] = useState(true);
  const [includeClass, setIncludeClass] = useState(true);
  const [includeAbsentNo, setIncludeAbsentNo] = useState(true);
  const [mcPoints, setMcPoints] = useState(2);
  const [essayPoints, setEssayPoints] = useState(0);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  // Utility to parse LaTeX from string and convert to docx components
  const parseLatexToDocxComponents = (text: string) => {
    if (!text) return [];

    // Split text by $...$ and $$...$$
    const parts = text.split(/(\$\$[\s\S]*?\$\$|\$[^$]*?\$)/g);

    return parts.map(part => {
      if (part.startsWith('$$') && part.endsWith('$$')) {
        const mathContent = part.slice(2, -2).trim();
        return new Math({ children: [new TextRun(mathContent)] });
      } else if (part.startsWith('$') && part.endsWith('$')) {
        const mathContent = part.slice(1, -1).trim();
        return new Math({ children: [new TextRun(mathContent)] });
      } else {
        return new TextRun(part);
      }
    });
  };

  // Utility to convert Base64 to ArrayBuffer for docx ImageRun
  const base64ToArrayBuffer = (base64: string) => {
    const binaryString = window.atob(base64.split(',')[1]);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  };

  const formatQuestionsToText = useCallback(() => {
    let text = `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n\n`;
    questions.forEach((q, index) => {
      text += `${index + 1}. ${q.pertanyaan}\n`;
      if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
        q.pilihan.forEach((option, i) => {
          text += `   ${String.fromCharCode(97 + i)}. ${option}\n`;
        });
      }
      text += '\n';
    });
    return text;
  }, [questions, subject, language]);

  const handleCopy = useCallback(() => {
    const textToCopy = formatQuestionsToText();
    navigator.clipboard.writeText(textToCopy).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    });
  }, [formatQuestionsToText]);

  const handleDownloadAnswers = useCallback(() => {
    if (questions.length === 0) return;
    let content = language === 'id' ? `KUNCI JAWABAN\n` : `ANSWER KEY\n`;
    content += `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n`;
    content += `====================================\n\n`;
    const answerLines = questions.map((q, index) => {
        let line = `${index + 1}) `;
        if (q.tipe === QuestionType.MultipleChoice) {
            const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
            line += correctIndex !== -1 ? `${String.fromCharCode(97 + correctIndex)}. ${q.jawaban_benar}` : (q.jawaban_benar || '-');
        } else {
            line += q.jawaban_esai || '-';
        }
        return line;
    });
    content += answerLines.join('\n');
    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${language === 'id' ? 'kunci' : 'key'}_${subject.replace(/\s+/g, '_')}.txt`;
    link.click();
  }, [questions, subject, language]);

  const handleDownloadWord = useCallback(async () => {
    if (questions.length === 0) return;

    const children: any[] = [];

    // Title
    children.push(new Paragraph({
        text: subject,
        heading: HeadingLevel.HEADING_1,
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
    }));

    for (let index = 0; index < questions.length; index++) {
        const q = questions[index];

        // Question Text (with LaTeX support)
        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                ...parseLatexToDocxComponents(q.pertanyaan)
            ],
            spacing: { before: 200, after: 100 },
        }));

        // Embed Image if exists
        if (q.image_url) {
            try {
                const imageBuffer = base64ToArrayBuffer(q.image_url);
                children.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: { width: 300, height: 200 },
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 100, after: 100 },
                }));
            } catch (e) {
                console.error("Failed to embed image in Word:", e);
            }
        }

        // Options for Multiple Choice
        if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
            q.pilihan.forEach((option, idx) => {
                const letter = String.fromCharCode(97 + idx); 
                children.push(new Paragraph({
                    children: [
                        new TextRun({ text: `${letter}. `, bold: true }),
                        ...parseLatexToDocxComponents(option)
                    ],
                    indent: { left: 720 },
                    spacing: { after: 50 },
                }));
            });
        }

        // Space for Essay
        if (q.tipe === QuestionType.Essay) {
            children.push(new Paragraph({ text: "", spacing: { after: 600 } }));
        }
    }

    // --- Answer Key Section ---
    children.push(new Paragraph({ children: [new PageBreak()] }));
    children.push(new Paragraph({
        text: language === 'id' ? 'KUNCI JAWABAN' : 'ANSWER KEY',
        heading: HeadingLevel.HEADING_2,
        alignment: AlignmentType.CENTER,
        spacing: { after: 200 },
    }));

    questions.forEach((q, index) => {
        let answerContent: any[] = [];
        if (q.tipe === QuestionType.MultipleChoice) {
             const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
             const letter = correctIndex !== -1 ? String.fromCharCode(97 + correctIndex) + '. ' : '';
             answerContent = [new TextRun(letter), ...parseLatexToDocxComponents(q.jawaban_benar || '')];
        } else {
            answerContent = parseLatexToDocxComponents(q.jawaban_esai || "-");
        }

        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                ...answerContent
            ],
            spacing: { after: 100 },
        }));
    });

    const doc = new Document({
        sections: [{
            properties: {},
            children: children,
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${subject.replace(/\s+/g, '_')}.docx`;
    link.click();
    window.URL.revokeObjectURL(url);
  }, [questions, subject, language]);

  const handlePrint = () => {
    const contentNode = contentRef.current;
    if (!contentNode) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><head><title>${language === 'id' ? 'Cetak Soal' : 'Print Questions'}</title>`);
      const printStyles = `
        <style>
          body { font-family: 'Times New Roman', Times, serif; font-size: 12pt; color: #000; }
          h1 { font-size: 16pt; margin-bottom: 0.5rem; }
          h2 { font-size: 14pt; margin-bottom: 1.25rem; }
          p { margin: 0; padding: 0; line-height: 1.2; }
          .question-item { margin-bottom: 1rem; page-break-inside: avoid; }
          .choices { list-style-type: lower-alpha; padding-left: 2em; margin: 0; }
          .choices li { padding-left: 0.5em; line-height: 1.2; }
          img { max-width: 100%; height: auto; max-height: 300px; display: block; margin: 10px 0; }
          mjx-container { font-size: 1.03em !important; vertical-align: -0.05em; }
          .no-print { display: none !important; }
        </style>
      `;
      printWindow.document.write(printStyles);
      printWindow.document.write('</head><body>');
      printWindow.document.write(`<h1>${language === 'id' ? 'Materi' : 'Topic'}: ${subject}</h1><h2>${language === 'id' ? 'Daftar Soal' : 'Question List'}</h2>`);
      printWindow.document.write(contentRef.current.innerHTML);
      printWindow.document.write('</body></html>');
      printWindow.document.close();
      printWindow.focus();
      printWindow.onload = () => { printWindow.print(); printWindow.close(); };
    }
  };

  const generateGoogleAppsScript = useCallback(() => {
    const sanitizedSubject = subject.replace(/'/g, "\\'");
    const cleanQuestions = questions.map(({image_url, image_prompt, ...rest}) => rest);
    const questionsJSON = JSON.stringify(cleanQuestions, null, 2);
    const langStrings = language === 'id' ? {
        description: `Kuis tentang ${sanitizedSubject}`,
        logCreated: 'Formulir berhasil dibuat!',
        logUrl: 'URL: ',
        errorLog: 'Error soal #',
    } : {
        description: `Quiz about ${sanitizedSubject}`,
        logCreated: 'Form created successfully!',
        logUrl: 'URL: ',
        errorLog: 'Error question #',
    };

    return `function createQuizFromQuestions() {
  var form = FormApp.create('${sanitizedSubject}');
  form.setIsQuiz(true);
  ${includeName ? "form.addTextItem().setTitle('Nama Lengkap').setRequired(true);" : ""}
  ${includeClass ? "form.addTextItem().setTitle('Kelas').setRequired(true);" : ""}
  ${includeAbsentNo ? "form.addTextItem().setTitle('Nomor Absen').setRequired(true);" : ""}
  var questions = ${questionsJSON};
  questions.forEach(function(q, index) {
    if (q.tipe === '${QuestionType.MultipleChoice}') {
      var item = form.addMultipleChoiceItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${mcPoints});
      var choices = q.pilihan.map(function(opt) { return item.createChoice(opt, opt === q.jawaban_benar); });
      item.setChoices(choices);
    } else {
      form.addParagraphTextItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${essayPoints});
    }
  });
  Logger.log('${langStrings.logCreated} ' + form.getPublishedUrl());
}`;
}, [questions, subject, language, includeName, includeClass, includeAbsentNo, mcPoints, essayPoints]);

  const handleCopyGFormScript = useCallback(() => {
    if (gformScriptRef.current) {
        navigator.clipboard.writeText(gformScriptRef.current.value).then(() => {
            setIsGFormScriptCopied(true);
            setTimeout(() => setIsGFormScriptCopied(false), 2000);
        });
    }
  }, []);

  return (
    <>
      <div
        className={`fixed inset-0 z-40 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        aria-modal="true" role="dialog"
      >
        <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={onClose}></div>
        <div
          ref={panelRef}
          className={`fixed top-0 right-0 bottom-0 flex flex-col w-full max-w-xl bg-slate-800/80 backdrop-blur-xl border-l border-slate-700 shadow-2xl transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
        >
          <header className="flex items-center justify-between p-4 border-b border-slate-700 flex-shrink-0">
            <h2 className="text-xl font-bold text-white">{t('document_panel.title', {count: questions.length})}</h2>
            <div className="flex items-center gap-1 sm:gap-2">
              <Tooltip content={t('document_panel.download_answers_tooltip')}>
                  <button onClick={handleDownloadAnswers} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-green-400 rounded-full disabled:opacity-50"><KeyIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.google_form_tooltip')}>
                  <button onClick={() => setShowGFormModal(true)} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full disabled:opacity-50"><GoogleFormIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_word_tooltip')}>
                  <button onClick={handleDownloadWord} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><WordIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_pdf_tooltip')}>
                  <button onClick={handlePrint} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><PdfIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.copy_tooltip')}>
                  <button onClick={handleCopy} className="p-2 text-slate-400 hover:text-purple-400 rounded-full">{isCopied ? <CheckCircleIcon className="w-5 h-5 text-green-500"/> : <ClipboardIcon className="w-5 h-5" />}</button>
              </Tooltip>
              <Tooltip content={t('document_panel.clear_all_tooltip')}>
                  <button onClick={onClear} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-red-500 rounded-full disabled:opacity-50"><TrashIcon className="w-5 h-5" /></button>
              </Tooltip>
              <button onClick={onClose} className="p-2 text-slate-400 hover:text-white rounded-full"><XCircleIcon className="w-6 h-6" /></button>
            </div>
          </header>
          <div className="flex-grow p-6 overflow-y-auto">
            {questions.length > 0 ? (
              <div ref={contentRef} className="space-y-6">
                {questions.map((q, index) => (
                  <DocumentQuestionItem key={q.id} question={q} index={index} onRemove={onRemove} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-center text-slate-500">
                  <DocumentIcon className="w-16 h-16 mb-4" />
                  <h3 className="text-lg font-semibold text-slate-400">{t('document_panel.empty_title')}</h3>
                  <p>{t('document_panel.empty_description')}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {showGFormModal && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4" onClick={() => setShowGFormModal(false)}>
            <div className="bg-slate-800 border border-slate-600 rounded-lg shadow-xl max-w-2xl w-full p-6 flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold text-white">{showGFormConfig ? t('document_panel.gform_config_title') : t('document_panel.gform_help_title')}</h3>
                    <button onClick={() => setShowGFormModal(false)} className="p-1 text-slate-400 hover:text-white"><XCircleIcon className="w-6 h-6" /></button>
                </div>
                {showGFormConfig ? (
                    <div className="space-y-6 overflow-y-auto">
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_identity_label')}</h4>
                            <div className="space-y-2">
                                {[{s:includeName,f:setIncludeName,l:t('document_panel.gform_include_name')},{s:includeClass,f:setIncludeClass,l:t('document_panel.gform_include_class')},{s:includeAbsentNo,f:setIncludeAbsentNo,l:t('document_panel.gform_include_absent')}].map((item,i)=>(
                                    <label key={i} className="flex items-center cursor-pointer">
                                        <input type="checkbox" checked={item.s} onChange={e=>item.f(e.target.checked)} className="h-4 w-4 rounded bg-slate-700 text-purple-500" />
                                        <span className="ml-3 text-slate-300">{item.l}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_scoring_label')}</h4>
                            <div className="grid grid-cols-2 gap-4">
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_mc_points')}</label>
                                <input type="number" value={mcPoints} onChange={e=>setMcPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_essay_points')}</label>
                                <input type="number" value={essayPoints} onChange={e=>setEssayPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                            </div>
                        </div>
                        <button onClick={()=>setShowGFormConfig(false)} className="w-full bg-purple-600 text-white font-bold py-3 rounded-md">{t('document_panel.gform_generate_btn')}</button>
                    </div>
                ) : (
                    <div className="space-y-4 overflow-y-auto">
                        <textarea readOnly ref={gformScriptRef} value={generateGoogleAppsScript()} className="w-full h-40 bg-slate-900 border border-slate-600 rounded-md p-2 font-mono text-xs text-slate-300" />
                        <button onClick={handleCopyGFormScript} className={`w-full py-2 rounded-md ${isGFormScriptCopied?'bg-green-600':'bg-purple-600'} text-white`}>
                            {isGFormScriptCopied ? t('document_panel.gform_copied_button') : t('document_panel.gform_copy_button')}
                        </button>
                        <div className="flex justify-between mt-4">
                            <button onClick={()=>setShowGFormConfig(true)} className="text-slate-400 hover:text-white">{t('back_button')}</button>
                            <button onClick={()=>setShowGFormModal(false)} className="bg-purple-600 text-white px-4 py-2 rounded-md">{t('document_panel.word_help_button')}</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </>
  );
};

export default DocumentPanel;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Question, QuestionType } from '../types';
import XCircleIcon from './icons/XCircleIcon';
import TrashIcon from './icons/TrashIcon';
import PdfIcon from './icons/PdfIcon';
import ClipboardIcon from './icons/ClipboardIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import DocumentIcon from './icons/DocumentIcon';
import WordIcon from './icons/WordIcon';
import KeyIcon from './icons/KeyIcon';
import GoogleFormIcon from './icons/GoogleFormIcon';
import PrinterIcon from './icons/PrinterIcon';
import Tooltip from './Tooltip';
import { useTranslation } from '../LanguageContext';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, PageBreak, Math, ImageRun } from 'docx';

interface DocumentPanelProps {
  isOpen: boolean;
  onClose: () => void;
  questions: Question[];
  onRemove: (questionId: string) => void;
  onClear: () => void;
  subject: string;
}

declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

const DocumentQuestionItem: React.FC<{ question: Question; index: number; onRemove: (id: string) => void }> = ({ question, index, onRemove }) => {
    const itemRef = useRef<HTMLDivElement>(null);
    const { t } = useTranslation();

    useEffect(() => {
        if (window.MathJax && itemRef.current) {
            window.MathJax.typesetPromise([itemRef.current])
                .catch((err) => console.error('MathJax document item typesetting error:', err));
        }
    }, [question]); 

    return (
        <div ref={itemRef} className="question-item bg-slate-900/50 p-4 rounded-lg relative group prose prose-invert max-w-none">
             <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity not-prose no-print">
                <Tooltip content={t('document_panel.remove_item_tooltip')} position="left">
                    <button 
                        onClick={() => onRemove(question.id)}
                        className="p-1.5 text-slate-500 bg-slate-800 rounded-full hover:text-red-500 hover:bg-slate-700 transition-colors"
                        >
                            <TrashIcon className="w-4 h-4" />
                    </button>
                </Tooltip>
             </div>
            <div className="font-semibold text-slate-200 mb-2">
                <p>
                    <span className="font-bold mr-2">{index + 1}.</span>
                    {question.pertanyaan}
                </p>
            </div>

            {question.image_url && (
                <div className="my-2">
                    <img src={question.image_url} alt="Question Diagram" className="rounded-lg max-h-48 border border-slate-600" />
                </div>
            )}

            {question.tipe === QuestionType.MultipleChoice && question.pilihan && (
                <ol className="choices space-y-1 list-inside list-[lower-alpha] text-slate-300 pl-6">
                    {question.pilihan.map((option, i) => (
                        <li key={i}>{option}</li>
                    ))}
                </ol>
            )}
            {question.tipe === QuestionType.Essay && (
                <div className="mt-2 pl-6 no-print">
                    <p className="text-sm text-slate-400 italic">(Essay answer)</p>
                </div>
            )}
        </div>
    );
};


const DocumentPanel: React.FC<DocumentPanelProps> = ({
  isOpen,
  onClose,
  questions,
  onRemove,
  onClear,
  subject,
}) => {
  const { t, language } = useTranslation();
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  const [showGFormModal, setShowGFormModal] = useState(false);
  const [showGFormConfig, setShowGFormConfig] = useState(true); 
  const [isGFormScriptCopied, setIsGFormScriptCopied] = useState(false);
  const gformScriptRef = useRef<HTMLTextAreaElement>(null);

  const [includeName, setIncludeName] = useState(true);
  const [includeClass, setIncludeClass] = useState(true);
  const [includeAbsentNo, setIncludeAbsentNo] = useState(true);
  const [mcPoints, setMcPoints] = useState(2);
  const [essayPoints, setEssayPoints] = useState(0);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  // Utility to handle indolog and other LaTeX structures for Word
  const parseTextToRuns = (text: string) => {
    if (!text) return [];

    // Pattern to catch $...$ or $$...$$
    const parts = text.split(/(\$\$[\s\S]*?\$\$|\$[^$]*?\$)/g);
    const runs: any[] = [];

    parts.forEach(part => {
      if ((part.startsWith('$') && part.endsWith('$')) || (part.startsWith('$$') && part.endsWith('$$'))) {
        let cleanMath = part.replace(/^\$\$?|\$\$?$/g, '').trim();

        // Handle indolog specifically: \indolog{2}{8} -> ^2 log 8
        const indologRegex = /\\indolog\{([^}]+)\}\{([^}]+)\}/g;
        if (indologRegex.test(cleanMath)) {
             const subParts = cleanMath.split(/(\\indolog\{[^}]+\}\{[^}]+\})/g);
             subParts.forEach(sp => {
                const match = indologRegex.exec(sp);
                indologRegex.lastIndex = 0; // reset
                if (match) {
                    runs.push(new TextRun({ text: match[1], superScript: true }));
                    runs.push(new TextRun({ text: " log " }));
                    runs.push(new TextRun({ text: match[2] }));
                } else if (sp.trim()) {
                    runs.push(new Math({ children: [new TextRun(sp)] }));
                }
             });
        } else {
            runs.push(new Math({ children: [new TextRun(cleanMath)] }));
        }
      } else if (part) {
        runs.push(new TextRun(part));
      }
    });

    return runs;
  };

  const base64ToArrayBuffer = (base64: string) => {
    const binaryString = window.atob(base64.split(',')[1]);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  };

  const formatQuestionsToText = useCallback(() => {
    let text = `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n\n`;
    questions.forEach((q, index) => {
      text += `${index + 1}. ${q.pertanyaan}\n`;
      if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
        q.pilihan.forEach((option, i) => {
          text += `   ${String.fromCharCode(97 + i)}. ${option}\n`;
        });
      }
      text += '\n';
    });
    return text;
  }, [questions, subject, language]);

  const handleCopy = useCallback(() => {
    const textToCopy = formatQuestionsToText();
    navigator.clipboard.writeText(textToCopy).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    });
  }, [formatQuestionsToText]);

  const handleDownloadAnswers = useCallback(() => {
    if (questions.length === 0) return;
    let content = language === 'id' ? `KUNCI JAWABAN\n` : `ANSWER KEY\n`;
    content += `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n`;
    content += `====================================\n\n`;
    const answerLines = questions.map((q, index) => {
        let line = `${index + 1}) `;
        if (q.tipe === QuestionType.MultipleChoice) {
            const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
            line += correctIndex !== -1 ? `${String.fromCharCode(97 + correctIndex)}. ${q.jawaban_benar}` : (q.jawaban_benar || '-');
        } else {
            line += q.jawaban_esai || '-';
        }
        return line;
    });
    content += answerLines.join('\n');
    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${language === 'id' ? 'kunci' : 'key'}_${subject.replace(/\s+/g, '_')}.txt`;
    link.click();
  }, [questions, subject, language]);

  const handleDownloadWord = useCallback(async () => {
    if (questions.length === 0) return;

    const children: any[] = [];

    // Title
    children.push(new Paragraph({
        children: [new TextRun({ text: subject, bold: true, size: 32 })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
    }));

    for (let index = 0; index < questions.length; index++) {
        const q = questions[index];

        // Question
        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                ...parseTextToRuns(q.pertanyaan)
            ],
            spacing: { before: 200, after: 120 },
        }));

        if (q.image_url) {
            try {
                const imageBuffer = base64ToArrayBuffer(q.image_url);
                children.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: { width: 300, height: 200 },
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 120, after: 120 },
                }));
            } catch (e) {
                console.error("Failed to embed image in Word:", e);
            }
        }

        if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
            q.pilihan.forEach((option, idx) => {
                const letter = String.fromCharCode(97 + idx); 
                children.push(new Paragraph({
                    children: [
                        new TextRun({ text: `${letter}. `, bold: true }),
                        ...parseTextToRuns(option)
                    ],
                    indent: { left: 720 },
                    spacing: { after: 60 },
                }));
            });
        }

        if (q.tipe === QuestionType.Essay) {
            children.push(new Paragraph({ text: "", spacing: { after: 800 } }));
        }
    }

    // Answer Key
    children.push(new Paragraph({ children: [new PageBreak()] }));
    children.push(new Paragraph({
        children: [new TextRun({ text: language === 'id' ? 'KUNCI JAWABAN' : 'ANSWER KEY', bold: true, size: 28 })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 300 },
    }));

    questions.forEach((q, index) => {
        let answerRuns: any[] = [];
        if (q.tipe === QuestionType.MultipleChoice) {
             const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
             const letter = correctIndex !== -1 ? String.fromCharCode(97 + correctIndex) + '. ' : '';
             answerRuns = [new TextRun(letter), ...parseTextToRuns(q.jawaban_benar || '')];
        } else {
            answerRuns = parseTextToRuns(q.jawaban_esai || "-");
        }

        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                ...answerRuns
            ],
            spacing: { after: 120 },
        }));
    });

    const doc = new Document({
        styles: {
            default: {
                document: {
                    run: {
                        font: "Times New Roman",
                        size: 24, // 12pt
                    },
                },
            },
        },
        sections: [{
            properties: {},
            children: children,
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${subject.replace(/\s+/g, '_')}.docx`;
    link.click();
    window.URL.revokeObjectURL(url);
  }, [questions, subject, language]);

  const handlePrint = () => {
    const contentNode = contentRef.current;
    if (!contentNode) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><head><title>${language === 'id' ? 'Cetak Soal' : 'Print Questions'}</title>`);
      const printStyles = `
        <style>
          body { font-family: 'Times New Roman', Times, serif; font-size: 12pt; color: #000; }
          h1 { font-size: 16pt; margin-bottom: 0.5rem; }
          h2 { font-size: 14pt; margin-bottom: 1.25rem; }
          p { margin: 0; padding: 0; line-height: 1.2; }
          .question-item { margin-bottom: 1rem; page-break-inside: avoid; }
          .choices { list-style-type: lower-alpha; padding-left: 2em; margin: 0; }
          .choices li { padding-left: 0.5em; line-height: 1.2; }
          img { max-width: 100%; height: auto; max-height: 300px; display: block; margin: 10px 0; }
          mjx-container { font-size: 1.03em !important; vertical-align: -0.05em; }
          .no-print { display: none !important; }
        </style>
      `;
      printWindow.document.write(printStyles);
      printWindow.document.write('</head><body>');
      printWindow.document.write(`<h1>${language === 'id' ? 'Materi' : 'Topic'}: ${subject}</h1><h2>${language === 'id' ? 'Daftar Soal' : 'Question List'}</h2>`);
      printWindow.document.write(contentRef.current.innerHTML);
      printWindow.document.write('</body></html>');
      printWindow.document.close();
      printWindow.focus();
      printWindow.onload = () => { printWindow.print(); printWindow.close(); };
    }
  };

  const generateGoogleAppsScript = useCallback(() => {
    const sanitizedSubject = subject.replace(/'/g, "\\'");
    const cleanQuestions = questions.map(({image_url, image_prompt, ...rest}) => rest);
    const questionsJSON = JSON.stringify(cleanQuestions, null, 2);
    const langStrings = language === 'id' ? {
        description: `Kuis tentang ${sanitizedSubject}`,
        logCreated: 'Formulir berhasil dibuat!',
        logUrl: 'URL: ',
        errorLog: 'Error soal #',
    } : {
        description: `Quiz about ${sanitizedSubject}`,
        logCreated: 'Form created successfully!',
        logUrl: 'URL: ',
        errorLog: 'Error question #',
    };

    return `function createQuizFromQuestions() {
  var form = FormApp.create('${sanitizedSubject}');
  form.setIsQuiz(true);
  ${includeName ? "form.addTextItem().setTitle('Nama Lengkap').setRequired(true);" : ""}
  ${includeClass ? "form.addTextItem().setTitle('Kelas').setRequired(true);" : ""}
  ${includeAbsentNo ? "form.addTextItem().setTitle('Nomor Absen').setRequired(true);" : ""}
  var questions = ${questionsJSON};
  questions.forEach(function(q, index) {
    if (q.tipe === '${QuestionType.MultipleChoice}') {
      var item = form.addMultipleChoiceItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${mcPoints});
      var choices = q.pilihan.map(function(opt) { return item.createChoice(opt, opt === q.jawaban_benar); });
      item.setChoices(choices);
    } else {
      form.addParagraphTextItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${essayPoints});
    }
  });
  Logger.log('${langStrings.logCreated} ' + form.getPublishedUrl());
}`;
}, [questions, subject, language, includeName, includeClass, includeAbsentNo, mcPoints, essayPoints]);

  const handleCopyGFormScript = useCallback(() => {
    if (gformScriptRef.current) {
        navigator.clipboard.writeText(gformScriptRef.current.value).then(() => {
            setIsGFormScriptCopied(true);
            setTimeout(() => setIsGFormScriptCopied(false), 2000);
        });
    }
  }, []);

  return (
    <>
      <div
        className={`fixed inset-0 z-40 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        aria-modal="true" role="dialog"
      >
        <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={onClose}></div>
        <div
          ref={panelRef}
          className={`fixed top-0 right-0 bottom-0 flex flex-col w-full max-w-xl bg-slate-800/80 backdrop-blur-xl border-l border-slate-700 shadow-2xl transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
        >
          <header className="flex items-center justify-between p-4 border-b border-slate-700 flex-shrink-0">
            <h2 className="text-xl font-bold text-white">{t('document_panel.title', {count: questions.length})}</h2>
            <div className="flex items-center gap-1 sm:gap-2">
              <Tooltip content={t('document_panel.download_answers_tooltip')}>
                  <button onClick={handleDownloadAnswers} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-green-400 rounded-full disabled:opacity-50"><KeyIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.google_form_tooltip')}>
                  <button onClick={() => setShowGFormModal(true)} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full disabled:opacity-50"><GoogleFormIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_word_tooltip')}>
                  <button onClick={handleDownloadWord} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><WordIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_pdf_tooltip')}>
                  <button onClick={handlePrint} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><PdfIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.copy_tooltip')}>
                  <button onClick={handleCopy} className="p-2 text-slate-400 hover:text-purple-400 rounded-full">{isCopied ? <CheckCircleIcon className="w-5 h-5 text-green-500"/> : <ClipboardIcon className="w-5 h-5" />}</button>
              </Tooltip>
              <Tooltip content={t('document_panel.clear_all_tooltip')}>
                  <button onClick={onClear} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-red-500 rounded-full disabled:opacity-50"><TrashIcon className="w-5 h-5" /></button>
              </Tooltip>
              <button onClick={onClose} className="p-2 text-slate-400 hover:text-white rounded-full"><XCircleIcon className="w-6 h-6" /></button>
            </div>
          </header>
          <div className="flex-grow p-6 overflow-y-auto">
            {questions.length > 0 ? (
              <div ref={contentRef} className="space-y-6">
                {questions.map((q, index) => (
                  <DocumentQuestionItem key={q.id} question={q} index={index} onRemove={onRemove} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-center text-slate-500">
                  <DocumentIcon className="w-16 h-16 mb-4" />
                  <h3 className="text-lg font-semibold text-slate-400">{t('document_panel.empty_title')}</h3>
                  <p>{t('document_panel.empty_description')}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {showGFormModal && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4" onClick={() => setShowGFormModal(false)}>
            <div className="bg-slate-800 border border-slate-600 rounded-lg shadow-xl max-w-2xl w-full p-6 flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold text-white">{showGFormConfig ? t('document_panel.gform_config_title') : t('document_panel.gform_help_title')}</h3>
                    <button onClick={() => setShowGFormModal(false)} className="p-1 text-slate-400 hover:text-white"><XCircleIcon className="w-6 h-6" /></button>
                </div>
                {showGFormConfig ? (
                    <div className="space-y-6 overflow-y-auto">
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_identity_label')}</h4>
                            <div className="space-y-2">
                                {[{s:includeName,f:setIncludeName,l:t('document_panel.gform_include_name')},{s:includeClass,f:setIncludeClass,l:t('document_panel.gform_include_class')},{s:includeAbsentNo,f:setIncludeAbsentNo,l:t('document_panel.gform_include_absent')}].map((item,i)=>(
                                    <label key={i} className="flex items-center cursor-pointer">
                                        <input type="checkbox" checked={item.s} onChange={e=>item.f(e.target.checked)} className="h-4 w-4 rounded bg-slate-700 text-purple-500" />
                                        <span className="ml-3 text-slate-300">{item.l}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_scoring_label')}</h4>
                            <div className="grid grid-cols-2 gap-4">
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_mc_points')}</label>
                                <input type="number" value={mcPoints} onChange={e=>setMcPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_essay_points')}</label>
                                <input type="number" value={essayPoints} onChange={e=>setEssayPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                            </div>
                        </div>
                        <button onClick={()=>setShowGFormConfig(false)} className="w-full bg-purple-600 text-white font-bold py-3 rounded-md">{t('document_panel.gform_generate_btn')}</button>
                    </div>
                ) : (
                    <div className="space-y-4 overflow-y-auto">
                        <textarea readOnly ref={gformScriptRef} value={generateGoogleAppsScript()} className="w-full h-40 bg-slate-900 border border-slate-600 rounded-md p-2 font-mono text-xs text-slate-300" />
                        <button onClick={handleCopyGFormScript} className={`w-full py-2 rounded-md ${isGFormScriptCopied?'bg-green-600':'bg-purple-600'} text-white`}>
                            {isGFormScriptCopied ? t('document_panel.gform_copied_button') : t('document_panel.gform_copy_button')}
                        </button>
                        <div className="flex justify-between mt-4">
                            <button onClick={()=>setShowGFormConfig(true)} className="text-slate-400 hover:text-white">{t('back_button')}</button>
                            <button onClick={()=>setShowGFormModal(false)} className="bg-purple-600 text-white px-4 py-2 rounded-md">{t('document_panel.word_help_button')}</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </>
  );
};

export default DocumentPanel;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Question, QuestionType } from '../types';
import XCircleIcon from './icons/XCircleIcon';
import TrashIcon from './icons/TrashIcon';
import PdfIcon from './icons/PdfIcon';
import ClipboardIcon from './icons/ClipboardIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import DocumentIcon from './icons/DocumentIcon';
import WordIcon from './icons/WordIcon';
import KeyIcon from './icons/KeyIcon';
import GoogleFormIcon from './icons/GoogleFormIcon';
import PrinterIcon from './icons/PrinterIcon';
import Tooltip from './Tooltip';
import { useTranslation } from '../LanguageContext';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, PageBreak, Math, ImageRun } from 'docx';

interface DocumentPanelProps {
  isOpen: boolean;
  onClose: () => void;
  questions: Question[];
  onRemove: (questionId: string) => void;
  onClear: () => void;
  subject: string;
}

declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

const DocumentQuestionItem: React.FC<{ question: Question; index: number; onRemove: (id: string) => void }> = ({ question, index, onRemove }) => {
    const itemRef = useRef<HTMLDivElement>(null);
    const { t } = useTranslation();

    useEffect(() => {
        if (window.MathJax && itemRef.current) {
            window.MathJax.typesetPromise([itemRef.current])
                .catch((err) => console.error('MathJax document item typesetting error:', err));
        }
    }, [question]); 

    return (
        <div ref={itemRef} className="question-item bg-slate-900/50 p-4 rounded-lg relative group prose prose-invert max-w-none">
             <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity not-prose no-print">
                <Tooltip content={t('document_panel.remove_item_tooltip')} position="left">
                    <button 
                        onClick={() => onRemove(question.id)}
                        className="p-1.5 text-slate-500 bg-slate-800 rounded-full hover:text-red-500 hover:bg-slate-700 transition-colors"
                        >
                            <TrashIcon className="w-4 h-4" />
                    </button>
                </Tooltip>
             </div>
            <div className="font-semibold text-slate-200 mb-2">
                <p>
                    <span className="font-bold mr-2">{index + 1}.</span>
                    {question.pertanyaan}
                </p>
            </div>

            {question.image_url && (
                <div className="my-2">
                    <img src={question.image_url} alt="Question Diagram" className="rounded-lg max-h-48 border border-slate-600" />
                </div>
            )}

            {question.tipe === QuestionType.MultipleChoice && question.pilihan && (
                <ol className="choices space-y-1 list-inside list-[lower-alpha] text-slate-300 pl-6">
                    {question.pilihan.map((option, i) => (
                        <li key={i}>{option}</li>
                    ))}
                </ol>
            )}
            {question.tipe === QuestionType.Essay && (
                <div className="mt-2 pl-6 no-print">
                    <p className="text-sm text-slate-400 italic">(Essay answer)</p>
                </div>
            )}
        </div>
    );
};


const DocumentPanel: React.FC<DocumentPanelProps> = ({
  isOpen,
  onClose,
  questions,
  onRemove,
  onClear,
  subject,
}) => {
  const { t, language } = useTranslation();
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  const [showGFormModal, setShowGFormModal] = useState(false);
  const [showGFormConfig, setShowGFormConfig] = useState(true); 
  const [isGFormScriptCopied, setIsGFormScriptCopied] = useState(false);
  const gformScriptRef = useRef<HTMLTextAreaElement>(null);

  const [includeName, setIncludeName] = useState(true);
  const [includeClass, setIncludeClass] = useState(true);
  const [includeAbsentNo, setIncludeAbsentNo] = useState(true);
  const [mcPoints, setMcPoints] = useState(2);
  const [essayPoints, setEssayPoints] = useState(0);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  // Comprehensive symbol mapper for non-linear math representation in Word
  const mapMathSymbols = (text: string) => {
    return text
      .replace(/\\le/g, '≤')
      .replace(/\\ge/g, '≥')
      .replace(/\\ne/g, '≠')
      .replace(/\\pm/g, '±')
      .replace(/\\times/g, '×')
      .replace(/\\div/g, '÷')
      .replace(/\\infty/g, '∞')
      .replace(/\\pi/g, 'π')
      .replace(/\\int/g, '∫')
      .replace(/\\Delta/g, 'Δ')
      .replace(/\\theta/g, 'θ')
      .replace(/\\alpha/g, 'α')
      .replace(/\\beta/g, 'β')
      .replace(/\\sqrt/g, '√')
      .replace(/\\approx/g, '≈');
  };

  // Helper to parse math blocks into TextRuns (superscripts, subscripts, indolog)
  const parseMathToRuns = (mathText: string) => {
    const runs: any[] = [];

    // 1. Handle \indolog{base}{arg} -> ^{base} log arg
    const indologRegex = /\\indolog\{([^}]+)\}\{([^}]+)\}/g;
    let lastIdx = 0;
    let match;

    let processedText = mathText;

    // Special handling for common calculus/algebra structures
    // Simplified: handle simple ^ and _ if not inside a complex LaTeX command
    const parts = mapMathSymbols(processedText).split(/(\^\{[^}]+\}|\^.|_\{[^}]+\}|_.)/g);

    parts.forEach(part => {
        if (part.startsWith('^')) {
            const val = part.startsWith('^{') ? part.slice(2, -1) : part.slice(1);
            runs.push(new TextRun({ text: val, superScript: true }));
        } else if (part.startsWith('_')) {
            const val = part.startsWith('_{') ? part.slice(2, -1) : part.slice(1);
            runs.push(new TextRun({ text: val, subScript: true }));
        } else if (part.includes('\\indolog')) {
            // Further sub-parse indolog within this part
            const subParts = part.split(/(\\indolog\{[^}]+\}\{[^}]+\})/g);
            subParts.forEach(sp => {
                const m = /\\indolog\{([^}]+)\}\{([^}]+)\}/.exec(sp);
                if (m) {
                    runs.push(new TextRun({ text: m[1], superScript: true }));
                    runs.push(new TextRun({ text: ' log ' }));
                    runs.push(new TextRun({ text: m[2] }));
                } else {
                    runs.push(new TextRun(sp));
                }
            });
        } else if (part) {
            // For anything else, if it still looks like complex LaTeX, use docx Math object
            // otherwise just a standard TextRun
            if (part.includes('\\') || part.includes('{')) {
                runs.push(new Math({ children: [new TextRun(part)] }));
            } else {
                runs.push(new TextRun(part));
            }
        }
    });

    return runs;
  };

  const parseFullText = (text: string) => {
    if (!text) return [];

    // Split into Math ($...$) and Plain text
    const blocks = text.split(/(\$\$[\s\S]*?\$\$|\$[^$]*?\$)/g);
    const finalRuns: any[] = [];

    blocks.forEach(block => {
      if (block.startsWith('$')) {
        const cleanMath = block.replace(/^\$\$?|\$\$?$/g, '').trim();
        finalRuns.push(...parseMathToRuns(cleanMath));
      } else if (block) {
        finalRuns.push(new TextRun(block));
      }
    });

    return finalRuns;
  };

  const base64ToArrayBuffer = (base64: string) => {
    const binaryString = window.atob(base64.split(',')[1]);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  };

  const formatQuestionsToText = useCallback(() => {
    let text = `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n\n`;
    questions.forEach((q, index) => {
      text += `${index + 1}. ${q.pertanyaan}\n`;
      if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
        q.pilihan.forEach((option, i) => {
          text += `   ${String.fromCharCode(97 + i)}. ${option}\n`;
        });
      }
      text += '\n';
    });
    return text;
  }, [questions, subject, language]);

  const handleCopy = useCallback(() => {
    const textToCopy = formatQuestionsToText();
    navigator.clipboard.writeText(textToCopy).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    });
  }, [formatQuestionsToText]);

  const handleDownloadAnswers = useCallback(() => {
    if (questions.length === 0) return;
    let content = language === 'id' ? `KUNCI JAWABAN\n` : `ANSWER KEY\n`;
    content += `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n`;
    content += `====================================\n\n`;
    const answerLines = questions.map((q, index) => {
        let line = `${index + 1}) `;
        if (q.tipe === QuestionType.MultipleChoice) {
            const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
            line += correctIndex !== -1 ? `${String.fromCharCode(97 + correctIndex)}. ${q.jawaban_benar}` : (q.jawaban_benar || '-');
        } else {
            line += q.jawaban_esai || '-';
        }
        return line;
    });
    content += answerLines.join('\n');
    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${language === 'id' ? 'kunci' : 'key'}_${subject.replace(/\s+/g, '_')}.txt`;
    link.click();
  }, [questions, subject, language]);

  const handleDownloadWord = useCallback(async () => {
    if (questions.length === 0) return;

    const children: any[] = [];

    // Title
    children.push(new Paragraph({
        children: [new TextRun({ text: subject.toUpperCase(), bold: true, size: 28 })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
    }));

    for (let index = 0; index < questions.length; index++) {
        const q = questions[index];

        // Question Paragraph
        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                ...parseFullText(q.pertanyaan)
            ],
            spacing: { before: 200, after: 120 },
        }));

        // Image Handling
        if (q.image_url) {
            try {
                const imageBuffer = base64ToArrayBuffer(q.image_url);
                children.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: { width: 300, height: 200 },
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 120, after: 120 },
                }));
            } catch (e) {
                console.error("Failed to embed image in Word:", e);
            }
        }

        // Options
        if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
            q.pilihan.forEach((option, idx) => {
                const letter = String.fromCharCode(97 + idx); 
                children.push(new Paragraph({
                    children: [
                        new TextRun({ text: `${letter}. `, bold: true }),
                        ...parseFullText(option)
                    ],
                    indent: { left: 720 },
                    spacing: { after: 60 },
                }));
            });
        }

        // Add extra space for Essay
        if (q.tipe === QuestionType.Essay) {
            children.push(new Paragraph({ text: "", spacing: { after: 1000 } }));
        }
    }

    // --- Answer Key Page ---
    children.push(new Paragraph({ children: [new PageBreak()] }));
    children.push(new Paragraph({
        children: [new TextRun({ text: language === 'id' ? 'KUNCI JAWABAN' : 'ANSWER KEY', bold: true, size: 24 })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 300 },
    }));

    questions.forEach((q, index) => {
        let answerContent: any[] = [];
        if (q.tipe === QuestionType.MultipleChoice) {
             const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
             const letter = correctIndex !== -1 ? String.fromCharCode(97 + correctIndex) + '. ' : '';
             answerContent = [new TextRun(letter), ...parseFullText(q.jawaban_benar || '')];
        } else {
            answerContent = parseFullText(q.jawaban_esai || "-");
        }

        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true }),
                ...answerContent
            ],
            spacing: { after: 120 },
        }));
    });

    const doc = new Document({
        styles: {
            default: {
                document: {
                    run: {
                        font: "Times New Roman",
                        size: 24, // Word uses half-points (24 = 12pt)
                    },
                },
            },
        },
        sections: [{
            properties: {},
            children: children,
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${subject.replace(/\s+/g, '_')}.docx`;
    link.click();
    window.URL.revokeObjectURL(url);
  }, [questions, subject, language]);

  const handlePrint = () => {
    const contentNode = contentRef.current;
    if (!contentNode) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><head><title>${language === 'id' ? 'Cetak Soal' : 'Print Questions'}</title>`);
      const printStyles = `
        <style>
          body { font-family: 'Times New Roman', Times, serif; font-size: 12pt; color: #000; }
          h1 { font-size: 16pt; margin-bottom: 0.5rem; }
          h2 { font-size: 14pt; margin-bottom: 1.25rem; }
          p { margin: 0; padding: 0; line-height: 1.2; }
          .question-item { margin-bottom: 1rem; page-break-inside: avoid; }
          .choices { list-style-type: lower-alpha; padding-left: 2em; margin: 0; }
          .choices li { padding-left: 0.5em; line-height: 1.2; }
          img { max-width: 100%; height: auto; max-height: 300px; display: block; margin: 10px 0; }
          mjx-container { font-size: 1.03em !important; vertical-align: -0.05em; }
          .no-print { display: none !important; }
        </style>
      `;
      printWindow.document.write(printStyles);
      printWindow.document.write('</head><body>');
      printWindow.document.write(`<h1>${language === 'id' ? 'Materi' : 'Topic'}: ${subject}</h1><h2>${language === 'id' ? 'Daftar Soal' : 'Question List'}</h2>`);
      printWindow.document.write(contentRef.current.innerHTML);
      printWindow.document.write('</body></html>');
      printWindow.document.close();
      printWindow.focus();
      printWindow.onload = () => { printWindow.print(); printWindow.close(); };
    }
  };

  const generateGoogleAppsScript = useCallback(() => {
    const sanitizedSubject = subject.replace(/'/g, "\\'");
    const cleanQuestions = questions.map(({image_url, image_prompt, ...rest}) => rest);
    const questionsJSON = JSON.stringify(cleanQuestions, null, 2);
    const langStrings = language === 'id' ? {
        description: `Kuis tentang ${sanitizedSubject}`,
        logCreated: 'Formulir berhasil dibuat!',
        logUrl: 'URL: ',
        errorLog: 'Error soal #',
    } : {
        description: `Quiz about ${sanitizedSubject}`,
        logCreated: 'Form created successfully!',
        logUrl: 'URL: ',
        errorLog: 'Error question #',
    };

    return `function createQuizFromQuestions() {
  var form = FormApp.create('${sanitizedSubject}');
  form.setIsQuiz(true);
  ${includeName ? "form.addTextItem().setTitle('Nama Lengkap').setRequired(true);" : ""}
  ${includeClass ? "form.addTextItem().setTitle('Kelas').setRequired(true);" : ""}
  ${includeAbsentNo ? "form.addTextItem().setTitle('Nomor Absen').setRequired(true);" : ""}
  var questions = ${questionsJSON};
  questions.forEach(function(q, index) {
    if (q.tipe === '${QuestionType.MultipleChoice}') {
      var item = form.addMultipleChoiceItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${mcPoints});
      var choices = q.pilihan.map(function(opt) { return item.createChoice(opt, opt === q.jawaban_benar); });
      item.setChoices(choices);
    } else {
      form.addParagraphTextItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${essayPoints});
    }
  });
  Logger.log('${langStrings.logCreated} ' + form.getPublishedUrl());
}`;
}, [questions, subject, language, includeName, includeClass, includeAbsentNo, mcPoints, essayPoints]);

  const handleCopyGFormScript = useCallback(() => {
    if (gformScriptRef.current) {
        navigator.clipboard.writeText(gformScriptRef.current.value).then(() => {
            setIsGFormScriptCopied(true);
            setTimeout(() => setIsGFormScriptCopied(false), 2000);
        });
    }
  }, []);

  return (
    <>
      <div
        className={`fixed inset-0 z-40 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        aria-modal="true" role="dialog"
      >
        <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={onClose}></div>
        <div
          ref={panelRef}
          className={`fixed top-0 right-0 bottom-0 flex flex-col w-full max-w-xl bg-slate-800/80 backdrop-blur-xl border-l border-slate-700 shadow-2xl transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
        >
          <header className="flex items-center justify-between p-4 border-b border-slate-700 flex-shrink-0">
            <h2 className="text-xl font-bold text-white">{t('document_panel.title', {count: questions.length})}</h2>
            <div className="flex items-center gap-1 sm:gap-2">
              <Tooltip content={t('document_panel.download_answers_tooltip')}>
                  <button onClick={handleDownloadAnswers} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-green-400 rounded-full disabled:opacity-50"><KeyIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.google_form_tooltip')}>
                  <button onClick={() => setShowGFormModal(true)} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full disabled:opacity-50"><GoogleFormIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_word_tooltip')}>
                  <button onClick={handleDownloadWord} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><WordIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_pdf_tooltip')}>
                  <button onClick={handlePrint} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><PdfIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.copy_tooltip')}>
                  <button onClick={handleCopy} className="p-2 text-slate-400 hover:text-purple-400 rounded-full">{isCopied ? <CheckCircleIcon className="w-5 h-5 text-green-500"/> : <ClipboardIcon className="w-5 h-5" />}</button>
              </Tooltip>
              <Tooltip content={t('document_panel.clear_all_tooltip')}>
                  <button onClick={onClear} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-red-500 rounded-full disabled:opacity-50"><TrashIcon className="w-5 h-5" /></button>
              </Tooltip>
              <button onClick={onClose} className="p-2 text-slate-400 hover:text-white rounded-full"><XCircleIcon className="w-6 h-6" /></button>
            </div>
          </header>
          <div className="flex-grow p-6 overflow-y-auto">
            {questions.length > 0 ? (
              <div ref={contentRef} className="space-y-6">
                {questions.map((q, index) => (
                  <DocumentQuestionItem key={q.id} question={q} index={index} onRemove={onRemove} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-center text-slate-500">
                  <DocumentIcon className="w-16 h-16 mb-4" />
                  <h3 className="text-lg font-semibold text-slate-400">{t('document_panel.empty_title')}</h3>
                  <p>{t('document_panel.empty_description')}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {showGFormModal && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4" onClick={() => setShowGFormModal(false)}>
            <div className="bg-slate-800 border border-slate-600 rounded-lg shadow-xl max-w-2xl w-full p-6 flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold text-white">{showGFormConfig ? t('document_panel.gform_config_title') : t('document_panel.gform_help_title')}</h3>
                    <button onClick={() => setShowGFormModal(false)} className="p-1 text-slate-400 hover:text-white"><XCircleIcon className="w-6 h-6" /></button>
                </div>
                {showGFormConfig ? (
                    <div className="space-y-6 overflow-y-auto">
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_identity_label')}</h4>
                            <div className="space-y-2">
                                {[{s:includeName,f:setIncludeName,l:t('document_panel.gform_include_name')},{s:includeClass,f:setIncludeClass,l:t('document_panel.gform_include_class')},{s:includeAbsentNo,f:setIncludeAbsentNo,l:t('document_panel.gform_include_absent')}].map((item,i)=>(
                                    <label key={i} className="flex items-center cursor-pointer">
                                        <input type="checkbox" checked={item.s} onChange={e=>item.f(e.target.checked)} className="h-4 w-4 rounded bg-slate-700 text-purple-500" />
                                        <span className="ml-3 text-slate-300">{item.l}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_scoring_label')}</h4>
                            <div className="grid grid-cols-2 gap-4">
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_mc_points')}</label>
                                <input type="number" value={mcPoints} onChange={e=>setMcPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_essay_points')}</label>
                                <input type="number" value={essayPoints} onChange={e=>setEssayPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                            </div>
                        </div>
                        <button onClick={()=>setShowGFormConfig(false)} className="w-full bg-purple-600 text-white font-bold py-3 rounded-md">{t('document_panel.gform_generate_btn')}</button>
                    </div>
                ) : (
                    <div className="space-y-4 overflow-y-auto">
                        <textarea readOnly ref={gformScriptRef} value={generateGoogleAppsScript()} className="w-full h-40 bg-slate-900 border border-slate-600 rounded-md p-2 font-mono text-xs text-slate-300" />
                        <button onClick={handleCopyGFormScript} className={`w-full py-2 rounded-md ${isGFormScriptCopied?'bg-green-600':'bg-purple-600'} text-white`}>
                            {isGFormScriptCopied ? t('document_panel.gform_copied_button') : t('document_panel.gform_copy_button')}
                        </button>
                        <div className="flex justify-between mt-4">
                            <button onClick={()=>setShowGFormConfig(true)} className="text-slate-400 hover:text-white">{t('back_button')}</button>
                            <button onClick={()=>setShowGFormModal(false)} className="bg-purple-600 text-white px-4 py-2 rounded-md">{t('document_panel.word_help_button')}</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </>
  );
};

export default DocumentPanel;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Question, QuestionType } from '../types';
import XCircleIcon from './icons/XCircleIcon';
import TrashIcon from './icons/TrashIcon';
import PdfIcon from './icons/PdfIcon';
import ClipboardIcon from './icons/ClipboardIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import DocumentIcon from './icons/DocumentIcon';
import WordIcon from './icons/WordIcon';
import KeyIcon from './icons/KeyIcon';
import GoogleFormIcon from './icons/GoogleFormIcon';
import PrinterIcon from './icons/PrinterIcon';
import Tooltip from './Tooltip';
import { useTranslation } from '../LanguageContext';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, PageBreak, Math, ImageRun } from 'docx';

interface DocumentPanelProps {
  isOpen: boolean;
  onClose: () => void;
  questions: Question[];
  onRemove: (questionId: string) => void;
  onClear: () => void;
  subject: string;
}

declare global {
    interface Window {
      MathJax: {
        typesetPromise: (elements?: HTMLElement[]) => Promise<void>;
      };
    }
}

const DocumentQuestionItem: React.FC<{ question: Question; index: number; onRemove: (id: string) => void }> = ({ question, index, onRemove }) => {
    const itemRef = useRef<HTMLDivElement>(null);
    const { t } = useTranslation();

    useEffect(() => {
        if (window.MathJax && itemRef.current) {
            window.MathJax.typesetPromise([itemRef.current])
                .catch((err) => console.error('MathJax document item typesetting error:', err));
        }
    }, [question]); 

    return (
        <div ref={itemRef} className="question-item bg-slate-900/50 p-4 rounded-lg relative group prose prose-invert max-w-none">
             <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity not-prose no-print">
                <Tooltip content={t('document_panel.remove_item_tooltip')} position="left">
                    <button 
                        onClick={() => onRemove(question.id)}
                        className="p-1.5 text-slate-500 bg-slate-800 rounded-full hover:text-red-500 hover:bg-slate-700 transition-colors"
                        >
                            <TrashIcon className="w-4 h-4" />
                    </button>
                </Tooltip>
             </div>
            <div className="font-semibold text-slate-200 mb-2">
                <p>
                    <span className="font-bold mr-2">{index + 1}.</span>
                    {question.pertanyaan}
                </p>
            </div>

            {question.image_url && (
                <div className="my-2">
                    <img src={question.image_url} alt="Question Diagram" className="rounded-lg max-h-48 border border-slate-600" />
                </div>
            )}

            {question.tipe === QuestionType.MultipleChoice && question.pilihan && (
                <ol className="choices space-y-1 list-inside list-[lower-alpha] text-slate-300 pl-6">
                    {question.pilihan.map((option, i) => (
                        <li key={i}>{option}</li>
                    ))}
                </ol>
            )}
            {question.tipe === QuestionType.Essay && (
                <div className="mt-2 pl-6 no-print">
                    <p className="text-sm text-slate-400 italic">(Essay answer)</p>
                </div>
            )}
        </div>
    );
};


const DocumentPanel: React.FC<DocumentPanelProps> = ({
  isOpen,
  onClose,
  questions,
  onRemove,
  onClear,
  subject,
}) => {
  const { t, language } = useTranslation();
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [isCopied, setIsCopied] = useState(false);
  const [showGFormModal, setShowGFormModal] = useState(false);
  const [showGFormConfig, setShowGFormConfig] = useState(true); 
  const [isGFormScriptCopied, setIsGFormScriptCopied] = useState(false);
  const gformScriptRef = useRef<HTMLTextAreaElement>(null);

  const [includeName, setIncludeName] = useState(true);
  const [includeClass, setIncludeClass] = useState(true);
  const [includeAbsentNo, setIncludeAbsentNo] = useState(true);
  const [mcPoints, setMcPoints] = useState(2);
  const [essayPoints, setEssayPoints] = useState(0);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  // Comprehensive symbol mapper for native Word representation
  const mapMathSymbolsToUnicode = (text: string) => {
    return text
      .replace(/\\le/g, '≤')
      .replace(/\\ge/g, '≥')
      .replace(/\\ne/g, '≠')
      .replace(/\\pm/g, '±')
      .replace(/\\times/g, '×')
      .replace(/\\cdot/g, '⋅')
      .replace(/\\div/g, '÷')
      .replace(/\\infty/g, '∞')
      .replace(/\\pi/g, 'π')
      .replace(/\\int/g, '∫')
      .replace(/\\Delta/g, 'Δ')
      .replace(/\\theta/g, 'θ')
      .replace(/\\alpha/g, 'α')
      .replace(/\\beta/g, 'β')
      .replace(/\\sqrt/g, '√')
      .replace(/\\approx/g, '≈')
      .replace(/\\ln/g, 'ln')
      .replace(/\\log/g, 'log')
      .replace(/\\partial/g, '∂')
      .replace(/\\sum/g, '∑')
      .replace(/\\rightarrow/g, '→')
      .replace(/\\Rightarrow/g, '⇒')
      .replace(/\\{/g, '{')
      .replace(/\\}/g, '}')
      .replace(/\\mid/g, '|');
  };

  // Converts LaTeX structure into Word's linear math format (UnicodeMath)
  // This helps Word auto-convert to "Professional" view more reliably
  const convertToUnicodeMath = (tex: string) => {
    let result = tex;
    // Fractions: \frac{a}{b} -> (a)/(b)
    while (result.includes('\\frac')) {
      result = result.replace(/\\frac\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}/g, '($1)/($2)');
    }
    // Roots: \sqrt{a} -> \sqrt(a)
    result = result.replace(/\\sqrt\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}/g, '√($1)');

    // Map symbols
    result = mapMathSymbolsToUnicode(result);

    // Clean up remaining LaTeX commands that are just variable names
    result = result.replace(/\\([a-zA-Z]+)/g, '$1');

    return result.trim();
  };

  const parseMathToRuns = (mathText: string) => {
    const runs: any[] = [];

    // Special handling for Indonesian Logarithm notation: \indolog{base}{arg}
    if (mathText.includes('\\indolog')) {
      const parts = mathText.split(/(\\indolog\{[^}]+\}\{[^}]+\})/g);
      parts.forEach(p => {
        const match = /\\indolog\{([^}]+)\}\{([^}]+)\}/.exec(p);
        if (match) {
          runs.push(new TextRun({ text: match[1], superScript: true, font: "Times New Roman" }));
          runs.push(new TextRun({ text: " log ", font: "Times New Roman" }));
          runs.push(new TextRun({ text: match[2], font: "Times New Roman" }));
        } else if (p.trim()) {
          const linear = convertToUnicodeMath(p);
          runs.push(new Math({ children: [new TextRun({ text: linear, font: "Cambria Math" })] }));
        }
      });
      return runs;
    }

    // Default: Convert whole block to UnicodeMath inside a Math container
    const linearMath = convertToUnicodeMath(mathText);
    runs.push(new Math({ 
      children: [new TextRun({ text: linearMath, font: "Cambria Math" })] 
    }));

    return runs;
  };

  const parseFullTextToRuns = (text: string) => {
    if (!text) return [];

    // Split text into Math blocks ($...$ or $$...$$) and Plain text
    const blocks = text.split(/(\$\$[\s\S]*?\$\$|\$[^$]*?\$)/g);
    const finalRuns: any[] = [];

    blocks.forEach(block => {
      if (block.startsWith('$')) {
        const cleanMath = block.replace(/^\$\$?|\$\$?$/g, '').trim();
        finalRuns.push(...parseMathToRuns(cleanMath));
      } else if (block) {
        finalRuns.push(new TextRun({ text: block, font: "Times New Roman" }));
      }
    });

    return finalRuns;
  };

  const base64ToArrayBuffer = (base64: string) => {
    const binaryString = window.atob(base64.split(',')[1]);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  };

  const formatQuestionsToText = useCallback(() => {
    let text = `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n\n`;
    questions.forEach((q, index) => {
      text += `${index + 1}. ${q.pertanyaan}\n`;
      if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
        q.pilihan.forEach((option, i) => {
          text += `   ${String.fromCharCode(97 + i)}. ${option}\n`;
        });
      }
      text += '\n';
    });
    return text;
  }, [questions, subject, language]);

  const handleCopy = useCallback(() => {
    const textToCopy = formatQuestionsToText();
    navigator.clipboard.writeText(textToCopy).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    });
  }, [formatQuestionsToText]);

  const handleDownloadAnswers = useCallback(() => {
    if (questions.length === 0) return;
    let content = language === 'id' ? `KUNCI JAWABAN\n` : `ANSWER KEY\n`;
    content += `${language === 'id' ? 'Materi' : 'Topic'}: ${subject}\n`;
    content += `====================================\n\n`;
    const answerLines = questions.map((q, index) => {
        let line = `${index + 1}) `;
        if (q.tipe === QuestionType.MultipleChoice) {
            const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
            line += correctIndex !== -1 ? `${String.fromCharCode(97 + correctIndex)}. ${q.jawaban_benar}` : (q.jawaban_benar || '-');
        } else {
            line += q.jawaban_esai || '-';
        }
        return line;
    });
    content += answerLines.join('\n');
    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${language === 'id' ? 'kunci' : 'key'}_${subject.replace(/\s+/g, '_')}.txt`;
    link.click();
  }, [questions, subject, language]);

  const handleDownloadWord = useCallback(async () => {
    if (questions.length === 0) return;

    const children: any[] = [];

    // Title
    children.push(new Paragraph({
        children: [new TextRun({ text: subject.toUpperCase(), bold: true, size: 28, font: "Times New Roman" })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
    }));

    for (let index = 0; index < questions.length; index++) {
        const q = questions[index];

        // Question Paragraph
        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true, font: "Times New Roman" }),
                ...parseFullTextToRuns(q.pertanyaan)
            ],
            spacing: { before: 200, after: 120 },
        }));

        // Image Section
        if (q.image_url) {
            try {
                const imageBuffer = base64ToArrayBuffer(q.image_url);
                children.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: { width: 300, height: 200 },
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 120, after: 120 },
                }));
            } catch (e) {
                console.error("Failed to embed image in Word:", e);
            }
        }

        // Multiple Choice Options
        if (q.tipe === QuestionType.MultipleChoice && q.pilihan) {
            q.pilihan.forEach((option, idx) => {
                const letter = String.fromCharCode(97 + idx); 
                children.push(new Paragraph({
                    children: [
                        new TextRun({ text: `${letter}. `, bold: true, font: "Times New Roman" }),
                        ...parseFullTextToRuns(option)
                    ],
                    indent: { left: 720 },
                    spacing: { after: 60 },
                }));
            });
        }

        // Space for Essay response if applicable
        if (q.tipe === QuestionType.Essay) {
            children.push(new Paragraph({ text: "", spacing: { after: 1000 } }));
        }
    }

    // --- Page Break & Answer Key ---
    children.push(new Paragraph({ children: [new PageBreak()] }));
    children.push(new Paragraph({
        children: [new TextRun({ text: language === 'id' ? 'KUNCI JAWABAN' : 'ANSWER KEY', bold: true, size: 24, font: "Times New Roman" })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 300 },
    }));

    questions.forEach((q, index) => {
        let answerContent: any[] = [];
        if (q.tipe === QuestionType.MultipleChoice) {
             const correctIndex = q.pilihan?.findIndex(p => p === q.jawaban_benar) ?? -1;
             const letter = correctIndex !== -1 ? String.fromCharCode(97 + correctIndex) + '. ' : '';
             answerContent = [new TextRun({ text: letter, font: "Times New Roman" }), ...parseFullTextToRuns(q.jawaban_benar || '')];
        } else {
            answerContent = parseFullTextToRuns(q.jawaban_esai || "-");
        }

        children.push(new Paragraph({
            children: [
                new TextRun({ text: `${index + 1}. `, bold: true, font: "Times New Roman" }),
                ...answerContent
            ],
            spacing: { after: 120 },
        }));
    });

    const doc = new Document({
        styles: {
            default: {
                document: {
                    run: {
                        font: "Times New Roman",
                        size: 24, // 12pt (Word uses half-points)
                    },
                },
            },
        },
        sections: [{
            properties: {},
            children: children,
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${subject.replace(/\s+/g, '_')}.docx`;
    link.click();
    window.URL.revokeObjectURL(url);
  }, [questions, subject, language]);

  const handlePrint = () => {
    const contentNode = contentRef.current;
    if (!contentNode) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><head><title>${language === 'id' ? 'Cetak Soal' : 'Print Questions'}</title>`);
      const printStyles = `
        <style>
          body { font-family: 'Times New Roman', Times, serif; font-size: 12pt; color: #000; }
          h1 { font-size: 16pt; margin-bottom: 0.5rem; }
          h2 { font-size: 14pt; margin-bottom: 1.25rem; }
          p { margin: 0; padding: 0; line-height: 1.2; }
          .question-item { margin-bottom: 1rem; page-break-inside: avoid; }
          .choices { list-style-type: lower-alpha; padding-left: 2em; margin: 0; }
          .choices li { padding-left: 0.5em; line-height: 1.2; }
          img { max-width: 100%; height: auto; max-height: 300px; display: block; margin: 10px 0; }
          mjx-container { font-size: 1.03em !important; vertical-align: -0.05em; }
          .no-print { display: none !important; }
        </style>
      `;
      printWindow.document.write(printStyles);
      printWindow.document.write('</head><body>');
      printWindow.document.write(`<h1>${language === 'id' ? 'Materi' : 'Topic'}: ${subject}</h1><h2>${language === 'id' ? 'Daftar Soal' : 'Question List'}</h2>`);
      printWindow.document.write(contentRef.current.innerHTML);
      printWindow.document.write('</body></html>');
      printWindow.document.close();
      printWindow.focus();
      printWindow.onload = () => { printWindow.print(); printWindow.close(); };
    }
  };

  const generateGoogleAppsScript = useCallback(() => {
    const sanitizedSubject = subject.replace(/'/g, "\\'");
    const cleanQuestions = questions.map(({image_url, image_prompt, ...rest}) => rest);
    const questionsJSON = JSON.stringify(cleanQuestions, null, 2);
    const langStrings = language === 'id' ? {
        description: `Kuis tentang ${sanitizedSubject}`,
        logCreated: 'Formulir berhasil dibuat!',
        logUrl: 'URL: ',
        errorLog: 'Error soal #',
    } : {
        description: `Quiz about ${sanitizedSubject}`,
        logCreated: 'Form created successfully!',
        logUrl: 'URL: ',
        errorLog: 'Error question #',
    };

    return `function createQuizFromQuestions() {
  var form = FormApp.create('${sanitizedSubject}');
  form.setIsQuiz(true);
  ${includeName ? "form.addTextItem().setTitle('Nama Lengkap').setRequired(true);" : ""}
  ${includeClass ? "form.addTextItem().setTitle('Kelas').setRequired(true);" : ""}
  ${includeAbsentNo ? "form.addTextItem().setTitle('Nomor Absen').setRequired(true);" : ""}
  var questions = ${questionsJSON};
  questions.forEach(function(q, index) {
    if (q.tipe === '${QuestionType.MultipleChoice}') {
      var item = form.addMultipleChoiceItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${mcPoints});
      var choices = q.pilihan.map(function(opt) { return item.createChoice(opt, opt === q.jawaban_benar); });
      item.setChoices(choices);
    } else {
      form.addParagraphTextItem().setTitle((index+1) + ". " + q.pertanyaan).setPoints(${essayPoints});
    }
  });
  Logger.log('${langStrings.logCreated} ' + form.getPublishedUrl());
}`;
}, [questions, subject, language, includeName, includeClass, includeAbsentNo, mcPoints, essayPoints]);

  const handleCopyGFormScript = useCallback(() => {
    if (gformScriptRef.current) {
        navigator.clipboard.writeText(gformScriptRef.current.value).then(() => {
            setIsGFormScriptCopied(true);
            setTimeout(() => setIsGFormScriptCopied(false), 2000);
        });
    }
  }, []);

  return (
    <>
      <div
        className={`fixed inset-0 z-40 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        aria-modal="true" role="dialog"
      >
        <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={onClose}></div>
        <div
          ref={panelRef}
          className={`fixed top-0 right-0 bottom-0 flex flex-col w-full max-w-xl bg-slate-800/80 backdrop-blur-xl border-l border-slate-700 shadow-2xl transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
        >
          <header className="flex items-center justify-between p-4 border-b border-slate-700 flex-shrink-0">
            <h2 className="text-xl font-bold text-white">{t('document_panel.title', {count: questions.length})}</h2>
            <div className="flex items-center gap-1 sm:gap-2">
              <Tooltip content={t('document_panel.download_answers_tooltip')}>
                  <button onClick={handleDownloadAnswers} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-green-400 rounded-full disabled:opacity-50"><KeyIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.google_form_tooltip')}>
                  <button onClick={() => setShowGFormModal(true)} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full disabled:opacity-50"><GoogleFormIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_word_tooltip')}>
                  <button onClick={handleDownloadWord} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><WordIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.download_pdf_tooltip')}>
                  <button onClick={handlePrint} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-purple-400 rounded-full"><PdfIcon className="w-5 h-5" /></button>
              </Tooltip>
              <Tooltip content={t('document_panel.copy_tooltip')}>
                  <button onClick={handleCopy} className="p-2 text-slate-400 hover:text-purple-400 rounded-full">{isCopied ? <CheckCircleIcon className="w-5 h-5 text-green-500"/> : <ClipboardIcon className="w-5 h-5" />}</button>
              </Tooltip>
              <Tooltip content={t('document_panel.clear_all_tooltip')}>
                  <button onClick={onClear} disabled={questions.length === 0} className="p-2 text-slate-400 hover:text-red-500 rounded-full disabled:opacity-50"><TrashIcon className="w-5 h-5" /></button>
              </Tooltip>
              <button onClick={onClose} className="p-2 text-slate-400 hover:text-white rounded-full"><XCircleIcon className="w-6 h-6" /></button>
            </div>
          </header>
          <div className="flex-grow p-6 overflow-y-auto">
            {questions.length > 0 ? (
              <div ref={contentRef} className="space-y-6">
                {questions.map((q, index) => (
                  <DocumentQuestionItem key={q.id} question={q} index={index} onRemove={onRemove} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-center text-slate-500">
                  <DocumentIcon className="w-16 h-16 mb-4" />
                  <h3 className="text-lg font-semibold text-slate-400">{t('document_panel.empty_title')}</h3>
                  <p>{t('document_panel.empty_description')}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {showGFormModal && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4" onClick={() => setShowGFormModal(false)}>
            <div className="bg-slate-800 border border-slate-600 rounded-lg shadow-xl max-w-2xl w-full p-6 flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold text-white">{showGFormConfig ? t('document_panel.gform_config_title') : t('document_panel.gform_help_title')}</h3>
                    <button onClick={() => setShowGFormModal(false)} className="p-1 text-slate-400 hover:text-white"><XCircleIcon className="w-6 h-6" /></button>
                </div>
                {showGFormConfig ? (
                    <div className="space-y-6 overflow-y-auto">
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_identity_label')}</h4>
                            <div className="space-y-2">
                                {[{s:includeName,f:setIncludeName,l:t('document_panel.gform_include_name')},{s:includeClass,f:setIncludeClass,l:t('document_panel.gform_include_class')},{s:includeAbsentNo,f:setIncludeAbsentNo,l:t('document_panel.gform_include_absent')}].map((item,i)=>(
                                    <label key={i} className="flex items-center cursor-pointer">
                                        <input type="checkbox" checked={item.s} onChange={e=>item.f(e.target.checked)} className="h-4 w-4 rounded bg-slate-700 text-purple-500" />
                                        <span className="ml-3 text-slate-300">{item.l}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                        <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700">
                            <h4 className="font-bold text-slate-200 mb-3">{t('document_panel.gform_scoring_label')}</h4>
                            <div className="grid grid-cols-2 gap-4">
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_mc_points')}</label>
                                <input type="number" value={mcPoints} onChange={e=>setMcPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                                <div><label className="block text-sm text-slate-400 mb-1">{t('document_panel.gform_essay_points')}</label>
                                <input type="number" value={essayPoints} onChange={e=>setEssayPoints(parseInt(e.target.value)||0)} className="w-full bg-slate-800 border border-slate-600 rounded-md p-2 text-white" /></div>
                            </div>
                        </div>
                        <button onClick={()=>setShowGFormConfig(false)} className="w-full bg-purple-600 text-white font-bold py-3 rounded-md">{t('document_panel.gform_generate_btn')}</button>
                    </div>
                ) : (
                    <div className="space-y-4 overflow-y-auto">
                        <textarea readOnly ref={gformScriptRef} value={generateGoogleAppsScript()} className="w-full h-40 bg-slate-900 border border-slate-600 rounded-md p-2 font-mono text-xs text-slate-300" />
                        <button onClick={handleCopyGFormScript} className={`w-full py-2 rounded-md ${isGFormScriptCopied?'bg-green-600':'bg-purple-600'} text-white`}>
                            {isGFormScriptCopied ? t('document_panel.gform_copied_button') : t('document_panel.gform_copy_button')}
                        </button>
                        <div className="flex justify-between mt-4">
                            <button onClick={()=>setShowGFormConfig(true)} className="text-slate-400 hover:text-white">{t('back_button')}</button>
                            <button onClick={()=>setShowGFormModal(false)} className="bg-purple-600 text-white px-4 py-2 rounded-md">{t('document_panel.word_help_button')}</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      )}
    </>
  );
};

export default DocumentPanel;
